-- 0049: per-rappel descent breakdown.
-- routes.rappels is a single free-text summary of the descent (see 0013). The route
-- detail UI now renders a "Rappels" section alongside the existing pitch-by-pitch
-- breakdown (pitch_detail), so we need the same shape for the descent: an ordered
-- array of individual rappels, each with a length, anchor type, and notes.
alter table routes
  add column if not exists rappel_detail     jsonb,  -- [{ n, lengthM, anchor, notes }, ...] ordered top to bottom
  add column if not exists rappel_count_note text;    -- optional short note on count variability (conditions/season), shown above the list

comment on column routes.rappel_detail is 'Ordered per-rappel breakdown for the Rappels section: [{ n, lengthM, anchor, notes }]. Null/absent when the standard descent is a walk-off, a single rappel, or has no reconstructable sequence.';
comment on column routes.rappel_count_note is 'Short note on rappel-count variability (e.g. conditions/season-dependent), shown above the Rappels list.';

-- Populated via 12 parallel research/synthesis passes over existing descent_text
-- beta (guidebook/trip-report/AAC-sourced). Structures each route's already-
-- researched descent into an ordered per-rappel breakdown. 118 of 187 candidate
-- WA alpine multi-pitch routes qualified (>=2 reconstructable rappels); the rest
-- (walk-offs, single rappels, undocumented sequences) are intentionally left null.

update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "natural (slung horn/block, occasional aged tat)", "notes": "First rappel off the upper East Ridge as it steepens toward a buttress; length is approximate since the source doesn''t give an exact figure for the crest variant."}, {"n": 2, "lengthM": 30, "anchor": "natural (horn/block, inspect any tat before trusting it)", "notes": "Continues down the buttress-like section of ridge; loose rock is a constant hazard here."}, {"n": 3, "lengthM": 30, "anchor": "natural (horn/block or gear anchor)", "notes": "Mid-sequence rappel bypassing steep/loose ground beside the ridge crest."}, {"n": 4, "lengthM": 30, "anchor": "natural (horn/block, some fixed webbing)", "notes": "Alternative parties instead downclimb a loose gully just to climber''s right of this rap line."}, {"n": 5, "lengthM": 30, "anchor": "natural (horn/block)", "notes": "Progressively nearing the C-J col; ropes should be handled carefully in the loose gully terrain to avoid dislodging rock."}, {"n": 6, "lengthM": 30, "anchor": "natural (horn/block, occasional tat)", "notes": "Second-to-last rappel of the ridge descent, still on loose, exposed terrain."}, {"n": 7, "lengthM": 30, "anchor": "natural (horn/block)", "notes": "Final rappel reaching the Cascade-Johannesburg col, after which the route joins Doug''s Direct traverse back toward Cascade Pass."}]'::jsonb, rappel_count_note = 'Trip reports vary (6-8 total): some parties do 2 full 60m rappels down a loose gully with natural anchors, others describe roughly 7 shorter raps off slings/tat directly on the ridge crest; the crest sequence below is the more commonly cited option.' where id = 'wa_johannesburg_mountain_northeast_buttress';
update routes set rappel_detail = '[{"n": 1, "lengthM": 55, "anchor": "natural gear anchor / slung horn", "notes": "First rappel off the top of the East Face; on the FA this rappel hung up and required a strenuous full return to the top to free it before continuing."}, {"n": 2, "lengthM": 55, "anchor": "natural gear anchor / slung horn", "notes": "Continues down the upper face on doubled/joined ropes; expect loose, sometimes rotten rock."}, {"n": 3, "lengthM": 55, "anchor": "natural gear anchor / slung chockstone", "notes": "Anchors angled closer to the northeast ridge than the ascent line to find sounder rock."}, {"n": 4, "lengthM": 55, "anchor": "natural gear anchor / slung horn", "notes": "Mid-face rappel; no fixed hardware exists anywhere on this route."}, {"n": 5, "lengthM": 55, "anchor": "natural gear anchor", "notes": "Continuing down the face away from the loosest fall-line terrain."}, {"n": 6, "lengthM": 55, "anchor": "natural gear anchor / slung block", "notes": "Wandering natural-anchor line increases risk of the rope getting stuck on the pull."}, {"n": 7, "lengthM": 55, "anchor": "natural gear anchor", "notes": "Roughly the halfway point of the face descent."}, {"n": 8, "lengthM": 55, "anchor": "natural gear anchor / slung horn", "notes": "Lower-face rappel; rock quality remains a defining hazard throughout."}, {"n": 9, "lengthM": 55, "anchor": "natural gear anchor", "notes": "Continues the doubled-rope descent toward easier ground."}, {"n": 10, "lengthM": 55, "anchor": "natural gear anchor / slung chockstone", "notes": "Approaching the lower face; watch for a night finish if the climb has run long."}, {"n": 11, "lengthM": 55, "anchor": "natural gear anchor", "notes": "Second-to-last stretch before the ground."}, {"n": 12, "lengthM": 55, "anchor": "natural gear anchor / slung horn", "notes": "Near the base; anchor building still required, no fixed stations to rely on."}, {"n": 13, "lengthM": 40, "anchor": "natural gear anchor", "notes": "Final rappel to the ground; the FA party finished around 3:30 a.m. and waded the creek chest-deep rather than re-enter the alder/devil''s club."}]'::jsonb, rappel_count_note = 'Based on a single documented FA descent (roughly a dozen-plus rappels down a 2,400-2,500 ft face); treat as a scaled estimate, not a fixed number, since anchor placement is judgment-call and can shift both length and count on a repeat descent.' where id = 'wa_the_devils_club';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "natural (loose block/horn, possible tat)", "notes": "First rappel off a major gendarme on the ridge crest heading toward East Fury; length is an assumed typical figure, not stated in the source."}, {"n": 2, "lengthM": 30, "anchor": "natural (block/horn, inspect existing tat)", "notes": "Continues past another pinnacle; anchors are improvised rather than fixed stations."}, {"n": 3, "lengthM": 30, "anchor": "natural (block/horn)", "notes": "Rockfall risk noted along this ridge; back up marginal-looking anchors where possible."}, {"n": 4, "lengthM": 30, "anchor": "natural (block/horn or tat)", "notes": "Getting off this notch/gendarme is effectively irreversible once ropes are pulled."}, {"n": 5, "lengthM": 30, "anchor": "natural (block/horn)", "notes": "Passes near the tower nicknamed the ''Pole of Remoteness''."}, {"n": 6, "lengthM": 30, "anchor": "natural (block/horn, possible tat)", "notes": "Mid-ridge rappel; retreat becomes progressively harder the farther the party commits."}, {"n": 7, "lengthM": 30, "anchor": "natural (block/horn)", "notes": "Continuing gendarme-to-gendarme along the crest."}, {"n": 8, "lengthM": 30, "anchor": "natural (block/horn or gear anchor)", "notes": "Another notch crossing; watch for loose rock dislodged by the rope."}, {"n": 9, "lengthM": 30, "anchor": "natural (block/horn)", "notes": "Nearing the East Fury side of the traverse."}, {"n": 10, "lengthM": 30, "anchor": "natural (block/horn, tat possible)", "notes": "Later-stage rappel of the ridge crossing."}, {"n": 11, "lengthM": 30, "anchor": "natural (block/horn)", "notes": "Second-to-last rappel before regaining East Fury''s upper terrain."}, {"n": 12, "lengthM": 30, "anchor": "natural (block/horn or gear anchor)", "notes": "Final rappel regaining East Fury, after which the descent continues via the Southeast Glacier route toward Luna Pass."}]'::jsonb, rappel_count_note = 'Source describes ''roughly a dozen'' rappels (12-13) getting off gendarmes/pinnacles along the connecting ridge; a rap rope has been reported severed by rockfall on a marginal anchor somewhere along this stretch, so treat every anchor with suspicion. Individual rappel lengths are not given in the source and are assumed typical single-rope lengths.' where id = 'wa_mount_fury_east_mongo_ridge';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "bolted chain anchor", "notes": "First of about 4 single-rope West Ridge rappels used to descend from the upper South Buttress terrain; mixed with significant downclimbing and route-finding through old tat stations."}, {"n": 2, "lengthM": 30, "anchor": "bolted chain anchor", "notes": "Continues down the West Ridge; a 60m rope is reportedly just long enough, 70m gives more margin."}, {"n": 3, "lengthM": 30, "anchor": "bolted chain anchor", "notes": "Mid-sequence West Ridge rappel toward easier ground."}, {"n": 4, "lengthM": 30, "anchor": "bolted chain anchor", "notes": "Final West Ridge rappel, generally considered the faster of the two descent options."}, {"n": 5, "lengthM": 30, "anchor": "fixed tat (dated webbing, back up recommended)", "notes": "First of the Complete route''s own two half-rope rappels down through a gap/notch on the lower ridge extension, back toward the ~6,500 ft contour."}, {"n": 6, "lengthM": 30, "anchor": "fixed tat (dated webbing, back up recommended)", "notes": "Second half-rope tat rappel through the lower ridge extension''s gaps, completing the return to the ~6,500 ft contour point and the off-trail return to the approach trail."}]'::jsonb, rappel_count_note = 'Sequence below uses the faster West Ridge option (about 4 raps) plus this route''s own two half-rope tat rappels on the lower ridge extension; a party can instead reverse the full buttress with 12+ rappels if the West Ridge isn''t desired, which would replace raps 1-4 with a longer sequence.' where id = 'wa_complete_south_buttress';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "natural (slung horn/block, occasional aging fixed webbing)", "notes": "First rappel drops from the summit into the notch just below/east of the top; check any sun-bleached tat before trusting it."}, {"n": 2, "lengthM": 30, "anchor": "natural (horn/block, tat possible)", "notes": "Continues down the peak''s back (east) side rather than reversing the approach gully."}, {"n": 3, "lengthM": 30, "anchor": "natural (horn/block)", "notes": "Watch for rope-stuck hazard pulling ropes through the blocky terrain."}, {"n": 4, "lengthM": 30, "anchor": "natural (horn/block, occasional tat)", "notes": "Nearing easier ground above the Silver Star Glacier basin."}, {"n": 5, "lengthM": 30, "anchor": "natural (horn/block)", "notes": "Final rappel reaching easy glacier snow/talus in the Silver Star Glacier basin; a 60m rope is tight in places, many parties use 70m or double ropes."}]'::jsonb, rappel_count_note = 'Source gives ''on the order of 4-5'' rappels total; 5 is used here as the representative figure.' where id = 'wa_pernod_spire_standard';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "mixed: fixed tat/slings on horn or block, some gear anchors", "notes": "Drops fairly directly down the ridge crest toward Black Tooth Notch; inspect any in-place webbing before trusting it."}, {"n": 2, "lengthM": 30, "anchor": "mixed: fixed tat/slings or gear anchor", "notes": "A traversing rappel trending skier''s-right/rappeller''s-left; keep the uphill rope end free and watch for pendulum swing."}, {"n": 3, "lengthM": 30, "anchor": "mixed: fixed tat/slings or gear anchor", "notes": "Second traversing rappel reaching Black Tooth Notch, the deep gap short of the summit block."}, {"n": 4, "lengthM": 30, "anchor": "fixed tat marking the station", "notes": "First of three rappels dropping straight down the fall line of the Southwest Couloir from Black Tooth Notch."}, {"n": 5, "lengthM": 30, "anchor": "fixed tat marking the station", "notes": "Continues down the couloir fall line; watch for loose rock and rockfall from parties above."}, {"n": 6, "lengthM": 30, "anchor": "fixed tat marking the station", "notes": "Final rappel before the couloir eases to class 3; from here a climber''s path leads down to the Park Creek Trail."}]'::jsonb, rappel_count_note = NULL where id = 'wa_goode_mountain_megalodon_ridge';
update routes set rappel_detail = '[{"n": 1, "lengthM": 55, "anchor": "granite rock anchor (check thoroughly)", "notes": "First of the south-facing ridge rappels; granite anchors here must be carefully inspected before trusting."}, {"n": 2, "lengthM": 55, "anchor": "granite rock anchor", "notes": "Continues down the south-facing terrain toward the Chickamin Glacier side."}, {"n": 3, "lengthM": 55, "anchor": "granite rock anchor", "notes": "Mid-sequence rappel; navigate near the bergschrund/crevasse field on the Chickamin Glacier."}, {"n": 4, "lengthM": 55, "anchor": "granite rock anchor", "notes": "Continuing descent; conditions and visibility can vary since descents are often finished in darkness."}, {"n": 5, "lengthM": 55, "anchor": "granite rock anchor", "notes": "Later-stage rappel approaching the lower slopes."}, {"n": 6, "lengthM": 55, "anchor": "granite rock anchor", "notes": "Second-to-last rappel before the final drop to the glacier."}, {"n": 7, "lengthM": 55, "anchor": "granite rock anchor, free-hanging", "notes": "Final rappel is free-hanging over the moat onto the Blue Glacier, typically done in darkness."}]'::jsonb, rappel_count_note = 'Source gives a 6-8 rappel range on 50-60m lines; 7 is used as the representative middle figure.' where id = 'wa_gunrunner';
update routes set rappel_detail = '[{"n": 1, "lengthM": 35, "anchor": "bolted anchor", "notes": "First rappel from the top of the buttress; nearly every station on this wall is bolted."}, {"n": 2, "lengthM": 35, "anchor": "gear anchor (one of the few non-bolted stations, near pitch 15)", "notes": "One of the rare non-bolted belays on the route; place directional gear if the pitch below overhangs."}, {"n": 3, "lengthM": 35, "anchor": "bolted anchor", "notes": "Continues down the upper wall; some pitches overhang enough to require a swing to reach the next station cleanly."}, {"n": 4, "lengthM": 35, "anchor": "bolted anchor", "notes": "Upper-wall rappel on fixed bolts."}, {"n": 5, "lengthM": 35, "anchor": "bolted anchor", "notes": "Continuing down the sustained 2,000 ft face."}, {"n": 6, "lengthM": 35, "anchor": "bolted anchor", "notes": "Mid-upper wall rappel."}, {"n": 7, "lengthM": 35, "anchor": "bolted anchor", "notes": "Retrieve any fixed lines left during the ascent as you pass them, per established practice on this route."}, {"n": 8, "lengthM": 35, "anchor": "bolted anchor", "notes": "Roughly the midpoint of the wall descent."}, {"n": 9, "lengthM": 35, "anchor": "bolted anchor", "notes": "Continuing down; expect the descent to take nearly as long as the climb."}, {"n": 10, "lengthM": 35, "anchor": "bolted anchor", "notes": "Mid-lower wall rappel."}, {"n": 11, "lengthM": 35, "anchor": "bolted anchor", "notes": "Lower-wall rappel on fixed bolts."}, {"n": 12, "lengthM": 35, "anchor": "bolted anchor", "notes": "Continuing toward the base of the buttress."}, {"n": 13, "lengthM": 35, "anchor": "bolted anchor", "notes": "Lower-wall rappel."}, {"n": 14, "lengthM": 35, "anchor": "bolted anchor", "notes": "Second-to-last-but-two rappel nearing the ground."}, {"n": 15, "lengthM": 35, "anchor": "bolted anchor", "notes": "Second-to-last rappel."}, {"n": 16, "lengthM": 35, "anchor": "bolted anchor", "notes": "Final rappel to the base; from here reverse the talus traverse around Lake Serene to the maintained trail."}]'::jsonb, rappel_count_note = 'Source describes two ways to size this: roughly 9-10 long single-strand rappels for the full wall using an uncut 70m rope station-to-station (as on the free variant Bluebell), or closer to 15-16 shorter rappels off every bolted ascent anchor. The 16-rappel, per-station sequence below is used as the more conservative/representative option given the overhanging terrain.' where id = 'wa_mount_index_north_norwegian_buttress';
update routes set rappel_detail = '[{"n": 1, "lengthM": 35, "anchor": "bolted/stainless-steel anchor", "notes": "First rappel from the top; plan on at least two ropes given the sustained overhanging terrain."}, {"n": 2, "lengthM": 35, "anchor": "bolted/stainless-steel anchor", "notes": "Continues down through overhanging ground; careful anchor/directional placement is critical near roofs."}, {"n": 3, "lengthM": 35, "anchor": "bolted/stainless-steel anchor", "notes": "Upper-wall rappel."}, {"n": 4, "lengthM": 35, "anchor": "bolted/stainless-steel anchor", "notes": "Continuing down the sustained overhanging pitches."}, {"n": 5, "lengthM": 35, "anchor": "bolted/stainless-steel anchor", "notes": "Upper-mid wall rappel."}, {"n": 6, "lengthM": 35, "anchor": "bolted/stainless-steel anchor", "notes": "Approaching the pitch 7 roof section below."}, {"n": 7, "lengthM": 35, "anchor": "bolted/stainless-steel anchor, roof section", "notes": "Covers the pitch that overhangs 40+ feet; this section requires either fixed lines or down-aiding to manage the roof."}, {"n": 8, "lengthM": 35, "anchor": "bolted/stainless-steel anchor", "notes": "Mid-wall rappel below the main roof."}, {"n": 9, "lengthM": 35, "anchor": "bolted/stainless-steel anchor", "notes": "Roughly the midpoint of the wall; the FA party''s long haul-bag-rider rappel spanned part of this middle section."}, {"n": 10, "lengthM": 35, "anchor": "bolted/stainless-steel anchor", "notes": "Continuing down mid-lower wall."}, {"n": 11, "lengthM": 35, "anchor": "bolted/stainless-steel anchor", "notes": "Lower-wall rappel."}, {"n": 12, "lengthM": 35, "anchor": "bolted/stainless-steel anchor", "notes": "Continuing toward the base."}, {"n": 13, "lengthM": 35, "anchor": "bolted/stainless-steel anchor", "notes": "Lower-wall rappel."}, {"n": 14, "lengthM": 35, "anchor": "bolted/stainless-steel anchor", "notes": "Nearing the ground."}, {"n": 15, "lengthM": 35, "anchor": "bolted/stainless-steel anchor", "notes": "Second-to-last rappel."}, {"n": 16, "lengthM": 35, "anchor": "bolted/stainless-steel anchor", "notes": "Final rappel to the base; remove any fixed lines left during the ascent as an established leave-no-trace practice on this route."}]'::jsonb, rappel_count_note = 'This aid line (16 pitches) is on the same buttress as North Norwegian Buttress/Bluebell, where a full descent can be done as ~9-10 long rappels with an uncut 70m rope or as ~15-16 shorter per-station rappels; 16 is used here since Jötnar''s sustained overhanging terrain generally calls for per-pitch directional gear placement. Note the FA party used an atypical technique — one climber rode the haul bags down roughly 1,000-1,200 ft before the team finished with conventional double-rope rappels — which is not necessarily standard practice for a repeat descent.' where id = 'wa_j_tnar';
update routes set rappel_detail = '[{"n": 1, "lengthM": 25, "anchor": "webbing anchor", "notes": "First rappel from the Blob''s summit ridge over a steep step at the edge of the Blob/Terror col; length is an approximate estimate, not stated in the source."}, {"n": 2, "lengthM": 25, "anchor": "webbing anchor", "notes": "Second rappel continuing down into the notch below; from the notch an easy scramble down the col returns climbers to the bench."}]'::jsonb, rappel_count_note = 'Source does not give specific lengths for these two rappels; figures below are rough single-rope-length estimates for a short col step, not precise measurements.' where id = 'wa_plan_9_from_outer_space';
update routes set rappel_detail = '[{"n": 1, "lengthM": 60, "anchor": "bolted chain anchor", "notes": "First rappel from the summit down to the Pitch 13 chain anchor, the commonly cited starting point for the descent."}, {"n": 2, "lengthM": 60, "anchor": "bolted chain anchor", "notes": "Continues down the ridge line on fixed chain/bolt anchors placed by the route developers for a secure descent."}, {"n": 3, "lengthM": 60, "anchor": "bolted chain anchor", "notes": "Mid-sequence rappel on the ridge; few pro bolts exist along this section besides the chain stations."}, {"n": 4, "lengthM": 60, "anchor": "bolted chain anchor", "notes": "Continuing down through the crusty ridge-running terrain."}, {"n": 5, "lengthM": 60, "anchor": "bolted chain anchor", "notes": "Rappel through the sustained slab section below the ridge."}, {"n": 6, "lengthM": 60, "anchor": "bolted chain anchor", "notes": "Second-to-last rappel nearing the bivy bench."}, {"n": 7, "lengthM": 60, "anchor": "bolted chain anchor", "notes": "Final rappel back to the good bivy bench near the base of the route."}]'::jsonb, rappel_count_note = 'Source only says ''several 60m rappels'' without an exact count; 7 is a rough representative estimate for descending this 14-pitch chain/bolt route with a 60m rope, and the true count could differ by a few depending on how the fixed stations line up.' where id = 'wa_concerto_in_c_for_drill_and_hammer';
update routes set rappel_detail = '[{"n": 1, "lengthM": 60, "anchor": "gear anchor (nut, per one documented descent)", "notes": "First of two ~200 ft rappels down steep slabs on the West Peak''s northwest side; a rope of at least 60m (or two ropes joined) is needed to reach the next stance."}, {"n": 2, "lengthM": 60, "anchor": "gear anchor (piton, per one documented descent)", "notes": "Second ~200 ft rappel reaching the approach basin; anchors here are improvised rather than fixed, so carry a small rack/cordage. Some parties finish this descent after dark."}]'::jsonb, rappel_count_note = NULL where id = 'wa_soviet_route';
update routes set rappel_detail = '[{"n": 1, "lengthM": 55, "anchor": "natural gear anchor (solid nut placement)", "notes": "First of the double-rope rappels down the uppermost West Ridge crest from the summit area; watch for loose, rockfall-prone rock."}, {"n": 2, "lengthM": 55, "anchor": "natural gear anchor", "notes": "Continues down the ridge crest; some stations traverse sideways to reach the next anchor and avoid fall lines."}, {"n": 3, "lengthM": 55, "anchor": "natural gear anchor", "notes": "Mid-ridge rappel; check any old fixed tat encountered for quality before trusting it."}, {"n": 4, "lengthM": 55, "anchor": "natural gear anchor", "notes": "Continues descending the ridge crest toward its lower section."}, {"n": 5, "lengthM": 55, "anchor": "natural gear anchor", "notes": "Lower-ridge rappel; terrain eases progressively below this point."}, {"n": 6, "lengthM": 55, "anchor": "natural gear anchor", "notes": "Continues down toward the toe of the ridge."}, {"n": 7, "lengthM": 60, "anchor": "natural gear anchor", "notes": "Final rappel reaching flat snow on the Terror Glacier at the toe of the ridge; re-rope immediately for crevasse hazard."}]'::jsonb, rappel_count_note = 'Text describes two distinct descent options: this ~7-rappel double-rope line down the full West Ridge on natural gear anchors (structured here as the more consolidated option), or alternatively a single-rope sequence of ~5 ridge rappels followed by ~9 more down the separate South Face (roughly 12-14 rappels total) — either is used depending on party preference and rope setup.' where id = 'wa_inspiration_peak_west_ridge';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "wrapped natural block/horn", "notes": "From the summit area, past old/misleading rappel tat, to a wrapped-block anchor; rappels roughly 30m (~100 ft) down to a stance."}, {"n": 2, "lengthM": 30, "anchor": "natural station (type not specified in source)", "notes": "After scrambling easy ledges from the first stance, an approximate, uncomplicated rappel lands in a moatless notch, from which the McAllister-Inspiration col is regained across steep crevassed terrain."}]'::jsonb, rappel_count_note = 'An alternative line (two long rappels straight down the north face on a 70m rope) is also used by some parties instead of this Northwest Ridge sequence.' where id = 'wa_dorado_needle_east_ridge';
update routes set rappel_detail = '[{"n": 1, "lengthM": 10, "anchor": "established rappel station (top of standard West Ridge route)", "notes": "Short rappel from just west of the true summit down into a gully southwest of the summit; approximate length, reported as roughly 25-30 ft."}, {"n": 2, "lengthM": 5, "anchor": "slung boulder (natural)", "notes": "Optional second, shorter rappel; confident parties often downclimb this at low 5th class instead."}]'::jsonb, rappel_count_note = 'Some sources describe these as two ~25m rappels rather than the shorter single-pitch lengths given here (~25-30ft and ~20ft) — carry a 50-60m rope to cover either version.' where id = 'wa_sherpa_peak_north_ridge';
update routes set rappel_detail = '[{"n": 1, "lengthM": 25, "anchor": "2-bolt station (sloping ledge)", "notes": "After downclimbing east ~100 ft through trees and loose rock from the summit area, first rappel down to an intermediate stance."}, {"n": 2, "lengthM": 30, "anchor": "bolted anchor", "notes": "Continues down into the Liberty Bell-Concord Tower notch; approximate length for a double-rope rappel, or split into two single-rope raps of similar combined length."}]'::jsonb, rappel_count_note = 'Descent funnels into the standard Liberty Bell notch descent shared with other summit-finishing routes on the peak; the second stage is done as one long double-rope rappel or, alternatively, as two shorter single-rope rappels depending on rack.' where id = 'wa_liberty_bell_independence_route';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "bolted chain anchor (ASCA rebolted 2010)", "notes": "First bolted station reached after downclimbing/simul-climbing the upper West Ridge from the true summit; single 60m rope."}, {"n": 2, "lengthM": 30, "anchor": "bolted chain anchor", "notes": "Second of three further rappels down the north/northwest side, interspersed with short downclimbs and a traverse back to the ridge crest."}, {"n": 3, "lengthM": 30, "anchor": "bolted chain anchor", "notes": "Continues down the north/northwest side of the upper ridge."}, {"n": 4, "lengthM": 30, "anchor": "bolted chain anchor", "notes": "Final of the four rappels; below it, downclimb loose exposed 3rd-class terrain and cross a cairned scree bowl back to the boulder field and approach trail."}]'::jsonb, rappel_count_note = 'This is the standard/faster West Ridge descent (4 bolted rappels) that most parties choose. An alternative reversing the South Buttress directly takes 12+ single-rope rappels with variable anchor quality (bolts plus some tat/tree anchors) and takes considerably longer.' where id = 'wa_cutthroat_south_buttress';
update routes set rappel_detail = '[{"n": 1, "lengthM": 60, "anchor": "bolted anchor (good bolts)", "notes": "From M&M Ledge, works climber''s left to a bolted station and begins the double-rope (2x60m) descent essentially straight down the East Face."}, {"n": 2, "lengthM": 60, "anchor": "bolted anchor", "notes": "Continues down the East Face on double ropes."}, {"n": 3, "lengthM": 60, "anchor": "bolted anchor", "notes": "Continues down the East Face on double ropes."}, {"n": 4, "lengthM": 60, "anchor": "bolted anchor", "notes": "Final rappel reaching the ground/talus at the base of the East Face."}]'::jsonb, rappel_count_note = 'This classic double-rope line (4 rappels) is the fastest and most commonly used descent today. Alternatives exist: a newer single-rope line with 6 bolted stations (reportedly tight on a couple with a 60m rope), or — if finishing to the true summit — the standard notch descent via two ~25m rappels.' where id = 'wa_liberty_crack';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "natural gear anchor (no fixed anchors documented; horns/cracks/slung blocks)", "notes": "Key technical rappel of the descent, from the final hoodoo tower down to a grassy ledge system, within the ~600 ft downclimb from the summit."}, {"n": 2, "lengthM": 25, "anchor": "natural gear anchor", "notes": "Past an exposed gendarme roughly at the Pitch 7 band on the west side of the ridge."}]'::jsonb, rappel_count_note = 'The lower rappel can reportedly be avoided/downclimbed in some conditions; carry a single 60m rope or two ropes to cover both.' where id = 'wa_spectre_peak_south_route';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "bolted chain anchor", "notes": "First bolted station on the shared West Ridge descent line used by routes on this peak, reached after downclimbing from the summit area."}, {"n": 2, "lengthM": 30, "anchor": "bolted chain anchor", "notes": "Second of three further rappels down the north/northwest side, with short downclimbs/traverses between stations."}, {"n": 3, "lengthM": 30, "anchor": "bolted chain anchor", "notes": "Continues down the north/northwest side of the upper ridge."}, {"n": 4, "lengthM": 30, "anchor": "bolted chain anchor", "notes": "Final rappel; below it, downclimb loose 3rd-class terrain and cross a scree bowl back toward the approach trail."}]'::jsonb, rappel_count_note = 'This route''s own text only says ''several rappels'' down the West Ridge without specifics; it shares the same standard West Ridge descent documented in detail for the neighboring South Buttress route on this peak (4 bolted chain rappels), structured here on that basis. An alternative reversing the South Buttress Direct line itself takes 12+ rappels of variable quality.' where id = 'wa_cutthroat_peak_r1';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "rock/gear anchor", "notes": "First of two rappels on a 70m rope (60m possible) used to bypass the icy summit gully; a documented station is located near 47.479°N, 120.832°W. Watch for loose rock."}, {"n": 2, "lengthM": 30, "anchor": "rock/gear anchor", "notes": "Continues down avoiding the ice slope toward Aasgard Pass; verify anchor integrity before committing."}]'::jsonb, rappel_count_note = 'This 2-rappel line is an icy/late-season alternate to the standard walk-off descent via the east ledges and summit gully (0 rappels normally); it''s used when that gully is icy, which is described as common late season.' where id = 'wa_dragontail_peak_backbone_ridge';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "double-bolt anchor (modern bolts)", "notes": "First of two rappels from the topout alcove/ledges down into Beckey Gully; this is the same rap line used by the standard Liberty Crack and Beckey Route descents."}, {"n": 2, "lengthM": 30, "anchor": "bolted anchor / tree station", "notes": "Second rappel lands near a tree anchor in Beckey Gully; from there, downclimb/walk the gully to the Liberty Bell-Concord notch."}]'::jsonb, rappel_count_note = 'Length reported as roughly 30m or ~80-100 ft depending on source — these are roughly equivalent, so ~30m is used as representative.' where id = 'wa_liberty_crack_free';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "natural/fixed sling on horn or block", "notes": "First rappel from the summit ridge, running close to straight down the ridgeline toward Black Tooth Notch."}, {"n": 2, "lengthM": 30, "anchor": "natural/fixed sling", "notes": "Second rappel, notably traversing (trending skier''s right/rappeller''s left)."}, {"n": 3, "lengthM": 30, "anchor": "natural/fixed sling", "notes": "Third rappel, also traversing, reaching Black Tooth Notch; from there scramble/simul-climb an exposed 4th-class connecting ledge."}, {"n": 4, "lengthM": 30, "anchor": "natural/fixed sling", "notes": "First of three further rappels down into the Southwest Couloir."}, {"n": 5, "lengthM": 30, "anchor": "natural/fixed sling", "notes": "Continues down the couloir."}, {"n": 6, "lengthM": 30, "anchor": "natural/fixed sling", "notes": "Final rappel into the Southwest Couloir, from which the descent continues toward North Fork Bridge Creek."}]'::jsonb, rappel_count_note = 'Six is the commonly cited/historical rappel count; some parties link stations differently and report as few as five. A single 60m rope suffices for every station.' where id = 'wa_mount_goode_northeast_buttress';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "not specified in source (loose gully terrain)", "notes": "First rappel in the steep, extremely loose descent gully, interspersed with 4th-class downclimbing."}, {"n": 2, "lengthM": 30, "anchor": "not specified in source", "notes": "Continues down the gully; loose rock hazard throughout."}, {"n": 3, "lengthM": 30, "anchor": "not specified in source", "notes": "Mid-gully rappel between downclimbing sections."}, {"n": 4, "lengthM": 30, "anchor": "not specified in source", "notes": "Continues descending the loose gully."}, {"n": 5, "lengthM": 30, "anchor": "not specified in source", "notes": "Final rappel of the representative sequence; total descent (including downclimbing) typically takes 2.5-3 hours in good conditions."}]'::jsonb, rappel_count_note = 'Source cites 4-6 rappels depending on party decisions and rope management; 5 is used as a representative middle count. Anchor type is not specified in the source — expect natural/gear anchors given the loose, unconsolidated rock described throughout, rather than documented bolted stations.' where id = 'wa_gato_negro';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "summit rap rings, station ~8ft south of summit bolts and ~4ft off the ground", "notes": "First rappel off the shared summit down to the P7 anchor on Mile High Club''s line; single 60m rope reaches comfortably."}, {"n": 2, "lengthM": 30, "anchor": "P7 bolted/fixed station", "notes": "A face-descent rappel down to the P6 anchor."}, {"n": 3, "lengthM": 15, "anchor": "P6 station", "notes": "A short rappel down to a ledge at P5; source explicitly flags this one as short."}, {"n": 4, "lengthM": 30, "anchor": "P5 ledge anchor", "notes": "Drops to P4, where one of two available anchor options is used."}, {"n": 5, "lengthM": 30, "anchor": "P4 anchor", "notes": "The most commonly botched rappel on the descent — aim for a 10-ft-tall tree roughly 15 ft skier''s-left of the climbing line; a hidden intermediate anchor is tucked in cedar bushes just below the visible upper-P3 station."}, {"n": 6, "lengthM": 30, "anchor": "upper-P3 station (cedar-bush anchor)", "notes": "Continues down to a lower-P3 anchor, landing on a large ledge."}, {"n": 7, "lengthM": 30, "anchor": "lower-P3 ledge anchor", "notes": "Drops to the P2 anchor."}, {"n": 8, "lengthM": 30, "anchor": "P2 anchor, finishing at P1", "notes": "Final rappel(s) via the P2 and P1 anchors bring you to the base of the route."}]'::jsonb, rappel_count_note = 'Individual rap lengths beyond the summit station aren''t separately measured in the source; used ~30m as a representative figure for a single 60m rope, shorter where the text calls out a ''short rap''.' where id = 'wa_beyond_redlining';
update routes set rappel_detail = '[{"n": 1, "lengthM": 55, "anchor": "bolted anchor, climber''s-left of M&M Ledge", "notes": "First of four double-rope rappels down the East Face, starting near M&M Ledge."}, {"n": 2, "lengthM": 55, "anchor": "bolted anchor", "notes": "Continues down the East Face line on double ropes."}, {"n": 3, "lengthM": 55, "anchor": "bolted anchor", "notes": "Continues down the East Face line on double ropes."}, {"n": 4, "lengthM": 55, "anchor": "bolted anchor", "notes": "Final rappel, reaching the ground at the base of the East Face."}]'::jsonb, rappel_count_note = 'Source doesn''t give per-rappel lengths, only ''four double-rope rappels essentially to the ground''; ~55m assumes near-full-length double-rope raps. A second, less-used option via the true summit and Liberty Bell notch (2 rappels of ~25m) exists but isn''t the one reflected here.' where id = 'wa_liberty_bell_thin_red_line';
update routes set rappel_detail = '[{"n": 1, "lengthM": 55, "anchor": "fixed pin/wire anchor (M&M Ledge)", "notes": "First rappel off M&M Ledge using two ropes, where the route joins Thin Red Line''s upper pitches and descent."}, {"n": 2, "lengthM": 55, "anchor": "bolted anchor, climber''s-left of M&M Ledge", "notes": "Moves onto Thin Red Line''s four bolted double-rope rappels down the East Face."}, {"n": 3, "lengthM": 55, "anchor": "bolted anchor", "notes": "Continues down the East Face line on double ropes."}, {"n": 4, "lengthM": 55, "anchor": "bolted anchor", "notes": "Continues down the East Face line on double ropes."}, {"n": 5, "lengthM": 55, "anchor": "bolted anchor", "notes": "Final rappel, reaching the ground at the base of the East Face."}]'::jsonb, rappel_count_note = 'Shares Thin Red Line''s lower descent from M&M Ledge down; exact length of the first rappel isn''t given in the source, so it''s approximated the same as the bolted raps below it.' where id = 'wa_a_servant_to_liberty';
update routes set rappel_detail = '[{"n": 1, "lengthM": 40, "anchor": "2-bolt double-ring stainless-steel anchor", "notes": "First rappel off the uppermost pitch of the main wall on the new SS anchors, roughly matching the ~40m top pitch."}, {"n": 2, "lengthM": 30, "anchor": "2-bolt double-ring stainless-steel anchor", "notes": "Continues down through a consecutive re-bolted belay station."}, {"n": 3, "lengthM": 30, "anchor": "2-bolt double-ring stainless-steel anchor", "notes": "Continues down through a consecutive re-bolted belay station."}, {"n": 4, "lengthM": 30, "anchor": "2-bolt double-ring stainless-steel anchor", "notes": "Continues down through a consecutive re-bolted belay station."}, {"n": 5, "lengthM": 30, "anchor": "2-bolt double-ring stainless-steel anchor", "notes": "Continues down through a consecutive re-bolted belay station."}, {"n": 6, "lengthM": 30, "anchor": "2-bolt double-ring stainless-steel anchor", "notes": "Continues down through a consecutive re-bolted belay station."}, {"n": 7, "lengthM": 30, "anchor": "2-bolt double-ring stainless-steel anchor", "notes": "Continues down through a consecutive re-bolted belay station."}, {"n": 8, "lengthM": 30, "anchor": "2-bolt double-ring stainless-steel anchor", "notes": "Final rappel down the main wall to the base; the remaining two approach pitches (5.8 bolted slab and a low-5th-class groove) are typically downclimbed or scrambled rather than rappelled."}]'::jsonb, rappel_count_note = 'Source doesn''t give an exact rappel tally, only that every belay has a new double-ring SS anchor. The 10 listed pitches include 2 disconnected approach pitches (an 80ft/5.8 bolted slab and a low-5th-class groove) that are normally scrambled/downclimbed rather than rappelled, so this reflects ~8 rappels down the main wall''s bolted belays; pitch lengths (~30-40m) are used as a proxy for rap lengths.' where id = 'wa_roan_wall_center_stage';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "sling around rock horn (natural)", "notes": "First rappel from the top of the north-face rock trough/arête down into the couloir, using a 60m rope."}, {"n": 2, "lengthM": 30, "anchor": "sling around rock horn (natural)", "notes": "Continues down the couloir; anchors built as needed on flanking rock."}, {"n": 3, "lengthM": 30, "anchor": "sling around rock horn (natural)", "notes": "Continues down the couloir."}, {"n": 4, "lengthM": 30, "anchor": "sling around rock horn (natural)", "notes": "Continues down the couloir."}, {"n": 5, "lengthM": 30, "anchor": "picket or v-thread (snow/ice)", "notes": "Anchor shifts to snow/ice protection where the couloir opens up."}, {"n": 6, "lengthM": 30, "anchor": "sling around rock horn (natural)", "notes": "Continues down the couloir on mixed terrain."}, {"n": 7, "lengthM": 30, "anchor": "picket or v-thread (snow/ice)", "notes": "Continues down the couloir."}, {"n": 8, "lengthM": 30, "anchor": "sling around rock horn (natural)", "notes": "Continues down the couloir."}, {"n": 9, "lengthM": 30, "anchor": "picket or v-thread (snow/ice)", "notes": "Continues down toward the lower couloir."}, {"n": 10, "lengthM": 30, "anchor": "picket or v-thread (snow/ice)", "notes": "Final rappel reaching the glacier/base of the couloir; where conditions allow, the lower section is sometimes downclimbed instead of rappelled."}]'::jsonb, rappel_count_note = 'Trip reports describe ''roughly ten'' 60m rappels down the couloir; the exact station-by-station anchor sequence isn''t documented, so this is a representative, approximate sequence with a mix of horn slings, occasional pickets/v-threads.' where id = 'wa_mount_shuksan_beckey_schmidtke';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "natural gear anchor (nut/cam) or sling, variable quality", "notes": "First of roughly 5 rappels down the upper West Ridge crest after downclimbing/rappelling off the summit area."}, {"n": 2, "lengthM": 30, "anchor": "natural gear anchor or sling, variable quality", "notes": "Continues down the West Ridge crest."}, {"n": 3, "lengthM": 30, "anchor": "natural gear anchor or sling, variable quality", "notes": "Continues down the West Ridge crest."}, {"n": 4, "lengthM": 30, "anchor": "natural gear anchor or sling, variable quality", "notes": "Continues down the West Ridge crest."}, {"n": 5, "lengthM": 30, "anchor": "natural gear anchor or sling, variable quality", "notes": "Final West Ridge rappel, reaching a scramble down to a notch where the South Face descent begins."}, {"n": 6, "lengthM": 30, "anchor": "fixed sling/rap station of variable quality or natural gear", "notes": "First of roughly 9 rappels down Inspiration''s South Face to regain the Terror Glacier."}, {"n": 7, "lengthM": 30, "anchor": "fixed sling/rap station or natural gear", "notes": "Continues down the South Face; some stations require a horizontal traverse to reach."}, {"n": 8, "lengthM": 30, "anchor": "fixed sling/rap station or natural gear", "notes": "Continues down the South Face."}, {"n": 9, "lengthM": 30, "anchor": "fixed sling/rap station or natural gear", "notes": "Continues down the South Face, with a horizontal traverse between some stations."}, {"n": 10, "lengthM": 30, "anchor": "fixed sling/rap station or natural gear", "notes": "Continues down the South Face."}, {"n": 11, "lengthM": 30, "anchor": "fixed sling/rap station or natural gear", "notes": "Continues down the South Face; some stations require a horizontal traverse to reach."}, {"n": 12, "lengthM": 30, "anchor": "fixed sling/rap station or natural gear", "notes": "Continues down the South Face."}, {"n": 13, "lengthM": 30, "anchor": "fixed sling/rap station or natural gear", "notes": "Continues down the South Face toward the glacier."}, {"n": 14, "lengthM": 60, "anchor": "fixed sling/rap station or natural gear", "notes": "Final rappel to the Terror Glacier, typically using a full 60-70m rope length."}]'::jsonb, rappel_count_note = 'Trip reports describe a range of about 12-14 total (roughly 5 down the upper West Ridge plus roughly 9 down the South Face); 14 used as the upper/most-cited figure. An alternate all-West-Ridge variant instead uses ~7 longer double-rope rappels and skips the South Face section entirely.' where id = 'wa_east_ridge_4';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "natural gear/horn anchor at the high notch", "notes": "A full rope-length, double-strand rappel that gets you below the crux crack pitch."}, {"n": 2, "lengthM": 30, "anchor": "mix of natural horns/blocks/trees and semi-fixed multi-strand sling stations", "notes": "Double-rope rappel along the ridge crest, interspersed with 3rd/4th-class downclimbing."}, {"n": 3, "lengthM": 30, "anchor": "mix of natural horns/blocks/trees and semi-fixed multi-strand sling stations", "notes": "Continues down the ridge crest with downclimbing between stations."}, {"n": 4, "lengthM": 30, "anchor": "mix of natural horns/blocks/trees and semi-fixed multi-strand sling stations", "notes": "Continues down the ridge crest."}, {"n": 5, "lengthM": 30, "anchor": "mix of natural horns/blocks/trees and semi-fixed multi-strand sling stations", "notes": "Continues down the ridge crest."}, {"n": 6, "lengthM": 30, "anchor": "mix of natural horns/blocks/trees and semi-fixed multi-strand sling stations", "notes": "Continues down the ridge crest."}, {"n": 7, "lengthM": 30, "anchor": "mix of natural horns/blocks/trees and semi-fixed multi-strand sling stations", "notes": "Continues down the ridge crest."}, {"n": 8, "lengthM": 30, "anchor": "mix of natural horns/blocks/trees and semi-fixed multi-strand sling stations", "notes": "Last of the double-rope rappels along the ridge crest, nearing the lower terrain."}, {"n": 9, "lengthM": 30, "anchor": "natural anchor (horn/block/tree)", "notes": "First of two shorter single-rope rappels as the ridge terrain eases."}, {"n": 10, "lengthM": 30, "anchor": "natural anchor (horn/block/tree)", "notes": "Final single-rope rappel before retracing the approach gully and lake traverse back to the col."}]'::jsonb, rappel_count_note = 'Trip reports cite a range of 6-11 total rappels depending on strategy and rope choice; used the centrally-cited ''typically 7-9 double-rope plus 2 single-rope'' figure (~10 total) as the representative sequence.' where id = 'wa_mount_triumph_northeast_ridge';
update routes set rappel_detail = '[{"n": 1, "lengthM": 40, "anchor": "2-bolt double-ring stainless-steel anchor (Center Stage''s top anchor)", "notes": "After traversing to a narrow ledge and downclimbing left to the top of Center Stage, the first rappel of Center Stage''s shared descent line."}, {"n": 2, "lengthM": 30, "anchor": "2-bolt double-ring stainless-steel anchor", "notes": "Continues down Center Stage''s re-bolted belay stations."}, {"n": 3, "lengthM": 30, "anchor": "2-bolt double-ring stainless-steel anchor", "notes": "Continues down Center Stage''s re-bolted belay stations."}, {"n": 4, "lengthM": 30, "anchor": "2-bolt double-ring stainless-steel anchor", "notes": "Continues down Center Stage''s re-bolted belay stations."}, {"n": 5, "lengthM": 30, "anchor": "2-bolt double-ring stainless-steel anchor", "notes": "Continues down Center Stage''s re-bolted belay stations."}, {"n": 6, "lengthM": 30, "anchor": "2-bolt double-ring stainless-steel anchor", "notes": "Continues down Center Stage''s re-bolted belay stations."}, {"n": 7, "lengthM": 30, "anchor": "2-bolt double-ring stainless-steel anchor", "notes": "Continues down Center Stage''s re-bolted belay stations."}, {"n": 8, "lengthM": 30, "anchor": "2-bolt double-ring stainless-steel anchor", "notes": "Final rappel down the main wall to the base, using Center Stage''s shared descent; the approach pitches below are typically downclimbed/scrambled rather than rappelled."}]'::jsonb, rappel_count_note = 'Source states the route joins the top of Center Stage and descends its bolted double-ring anchors, but doesn''t give an exact tally; used the same ~8-rappel figure established for Center Stage''s main-wall descent (the initial traverse/downclimb to reach it isn''t itself a rappel).' where id = 'wa_roan_wall_stage_right';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "fixed anchor (pin/sling)", "notes": "First rappel off the summit area on double ropes, capped near 30m."}, {"n": 2, "lengthM": 30, "anchor": "gear anchor (cams/nuts)", "notes": "Continues down the steep, complex east-ridge terrain; loose rock requires care with rope pull."}, {"n": 3, "lengthM": 30, "anchor": "fixed anchor (pin/sling)", "notes": "Continues down the ridge."}, {"n": 4, "lengthM": 30, "anchor": "gear anchor (cams/nuts)", "notes": "Continues down the ridge."}, {"n": 5, "lengthM": 30, "anchor": "fixed anchor (pin/sling)", "notes": "Continues down the ridge."}, {"n": 6, "lengthM": 30, "anchor": "gear anchor (cams/nuts)", "notes": "Continues down the ridge."}, {"n": 7, "lengthM": 30, "anchor": "fixed anchor (pin/sling)", "notes": "Continues down the ridge."}, {"n": 8, "lengthM": 30, "anchor": "gear anchor (cams/nuts)", "notes": "Continues down the ridge, nearing the col/bivy site."}, {"n": 9, "lengthM": 30, "anchor": "fixed anchor (pin/sling)", "notes": "Continues down toward the glacier."}, {"n": 10, "lengthM": 30, "anchor": "gear anchor (cams/nuts)", "notes": "Final rappel reaching the glacier below the tower."}]'::jsonb, rappel_count_note = 'Cited range is 10-12 rappels to 30m; 10 used as the representative sequence length.' where id = 'wa_nooksack_tower_beckey_route';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "Bolted/chain station in the descent gully", "notes": "First of three single-rope rappels down the standard South Arete gully after downclimbing from the Rabbit Ears; length is an approximation for a single 60m rope rappel, not stated per-pitch."}, {"n": 2, "lengthM": 30, "anchor": "Bolted/chain station", "notes": "Second rappel continuing down the gully."}, {"n": 3, "lengthM": 30, "anchor": "Bolted/chain station at base", "notes": "Final rappel to the base of the wall."}]'::jsonb, rappel_count_note = 'This describes the South Arete descent used to finish the full climb (downclimb to Rabbit Ears, then 3 raps). An alternate option is to rappel pitches 1-3 directly with a single 60m rope back to the ground instead of continuing to the summit.' where id = 'wa_mojo_rising';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "Bolted/chain station in gully", "notes": "First rappel below the Rabbit Ears after downclimbing the arete."}, {"n": 2, "lengthM": 30, "anchor": "Bolted/chain station", "notes": "Second rappel down the gully."}, {"n": 3, "lengthM": 30, "anchor": "Bolted/chain station at base", "notes": "Final rappel to the base."}]'::jsonb, rappel_count_note = 'Standard South Arete descent shared with other South Early Winters Spire routes; per-rap lengths are an approximation from the stated single 60m rope.' where id = 'wa_the_hitchhiker';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "Bolted/chain station in gully", "notes": "First rappel below the Rabbit Ears after downclimbing the arete''s short 5th-class step."}, {"n": 2, "lengthM": 30, "anchor": "Bolted/chain station", "notes": "Second rappel down the gully."}, {"n": 3, "lengthM": 30, "anchor": "Bolted/chain station at base", "notes": "Final rappel to the base."}]'::jsonb, rappel_count_note = 'Standard South Arete descent shared with other South Early Winters Spire routes; per-rap lengths approximated from the stated single 60m rope.' where id = 'wa_southern_man';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "Bolted anchor above the descent gully", "notes": "First rappel reached after downclimbing the South Arete''s short 5th-class section."}, {"n": 2, "lengthM": 30, "anchor": "Bolted/chain station", "notes": "Second rappel down the gully."}, {"n": 3, "lengthM": 30, "anchor": "Bolted/chain station at base", "notes": "Final rappel to the base of the wall."}]'::jsonb, rappel_count_note = 'Same shared South Arete gully descent used by other South Early Winters Spire routes; lengths approximated from the stated single 60m rope.' where id = 'wa_south_early_winter_spire_direct_east_buttress';
update routes set rappel_detail = '[{"n": 1, "lengthM": 70, "anchor": "Bolted station ~20-30 ft above the old P6 slung-block anchor", "notes": "Top anchor allowing a rappel from the very top of the route with double 70m ropes."}, {"n": 2, "lengthM": 70, "anchor": "Bolted or tree anchor", "notes": "Described generically as an ''obvious, good-quality anchor''; exact length not documented, approximated at full double-rope capacity."}, {"n": 3, "lengthM": 70, "anchor": "Bolted or tree anchor", "notes": "Same as above; individual rappel lengths aren''t broken out in the source."}, {"n": 4, "lengthM": 70, "anchor": "Bolted or tree anchor", "notes": "Continuing down the route on double ropes."}, {"n": 5, "lengthM": 70, "anchor": "Bolted or tree anchor", "notes": "Continuing down the route on double ropes."}, {"n": 6, "lengthM": 70, "anchor": "Bolted or tree anchor near base", "notes": "Final rappel to the ground; source only confirms anchors are trees or bolts, not exact spacing."}]'::jsonb, rappel_count_note = 'Text estimates 6-7 double-rope (70m) rappels to descend the full route; 6 used as representative. Note most parties actually take the walk-off instead of rappelling.' where id = 'wa_tooth_and_claw';
update routes set rappel_detail = '[{"n": 1, "lengthM": 40, "anchor": "Heavily slung summit boulder", "notes": "Drops down the middle of the upper face to a bolted ledge anchor."}, {"n": 2, "lengthM": 55, "anchor": "Bolted ledge anchor", "notes": "Down lichen-covered rock to a large ledge near a rock arch; traverse the ledge to a constriction with slings."}, {"n": 3, "lengthM": 55, "anchor": "Slings at a rock constriction", "notes": "Drops to a horn slung with blue webbing."}, {"n": 4, "lengthM": 40, "anchor": "Blue-slung horn", "notes": "Down to broad scree ledges."}, {"n": 5, "lengthM": 60, "anchor": "Scree ledge anchor", "notes": "Final rappel to the base of the first-pitch chimney."}]'::jsonb, rappel_count_note = 'Ultramega OK has no rappel line of its own; parties link into the North Face route''s standard 5-rappel descent.' where id = 'wa_ultramega_ok';
update routes set rappel_detail = '[{"n": 1, "lengthM": 55, "anchor": "Fixed nuts on the summit ridge (only reliable fixed anchor on route)", "notes": "Rappel east down the gully to the Pernod-Chablis notch."}, {"n": 2, "lengthM": 55, "anchor": "Natural anchor on steep slabs, unspecified and described as unreliable", "notes": "Continues down steep slabs toward the neve/snowfield."}, {"n": 3, "lengthM": 55, "anchor": "Natural anchor on steep slabs, unspecified and described as unreliable", "notes": "Final rappel reaching the neve/snowfield below; two 60m ropes are needed for these lower rappels."}]'::jsonb, rappel_count_note = 'Individual lengths aren''t given in feet/meters; approximated near double-rope (2x60m) capacity since exact per-rap distances aren''t documented.' where id = 'wa_direct_west_face';
update routes set rappel_detail = '[{"n": 1, "lengthM": 40, "anchor": "Heavily slung summit boulder", "notes": "First rappel of the shared North Face descent line."}, {"n": 2, "lengthM": 55, "anchor": "Bolts to a ledge near a rock arch", "notes": "Traverses to reach the next anchor."}, {"n": 3, "lengthM": 55, "anchor": "Sling at a rock constriction", "notes": "Drops to a slung horn."}, {"n": 4, "lengthM": 40, "anchor": "Slung horn", "notes": "Down to scree ledges."}, {"n": 5, "lengthM": 60, "anchor": "Scree ledge anchor", "notes": "Final rappel to the base of the first-pitch chimney, near Action Potential''s own start."}]'::jsonb, rappel_count_note = 'Nearly all parties finish via the North Face route''s standard 5-rappel descent rather than a line specific to Action Potential.' where id = 'wa_action_potential';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "Anchor at/near the North Ridge Notch (type unspecified)", "notes": "The one longer rappel that finishes the North Ridge reversal after several shorter roped downclimbs/rappels through the steeper fifth-class steps above; length is an estimate, not stated."}, {"n": 2, "lengthM": 30, "anchor": "Bolted/chain station", "notes": "First of the West Ridge''s standard 4-rappel sequence, single 60m rope sufficient."}, {"n": 3, "lengthM": 30, "anchor": "Bolted/chain station", "notes": "Second West Ridge rappel."}, {"n": 4, "lengthM": 30, "anchor": "Bolted/chain station", "notes": "Third West Ridge rappel."}, {"n": 5, "lengthM": 30, "anchor": "Bolted/chain station near boulder field", "notes": "Final West Ridge rappel down to the boulder field and trail."}]'::jsonb, rappel_count_note = 'Combines one longer rappel off the North Ridge into the notch with the standard 4-rappel West Ridge sequence; several additional short rappels/downclimbs on the upper North Ridge steps aren''t counted individually since the source doesn''t break them out. Lengths for the West Ridge portion are approximated from a single 60m rope.' where id = 'wa_north_ridge_3';
update routes set rappel_detail = '[{"n": 1, "lengthM": 70, "anchor": "Fixed/bolted anchor at top of the route", "notes": "First rappel down the line of ascent."}, {"n": 2, "lengthM": 70, "anchor": "Bolted/fixed anchor", "notes": "Continuing down the route."}, {"n": 3, "lengthM": 70, "anchor": "Bolted/fixed anchor", "notes": "Continuing down the route."}, {"n": 4, "lengthM": 70, "anchor": "Anchor above pitch 3, offset ~30 ft climber''s-left (a tree)", "notes": "Rappel off the tree here rather than straight down, per route beta."}, {"n": 5, "lengthM": 70, "anchor": "Bolted/fixed anchor", "notes": "Continuing down the route."}, {"n": 6, "lengthM": 70, "anchor": "Bolted/fixed anchor", "notes": "Below this point, manage rope carefully to avoid snagging in cracks/flakes near pitch 6."}, {"n": 7, "lengthM": 70, "anchor": "Bolted/fixed anchor", "notes": "Continuing down the route."}, {"n": 8, "lengthM": 70, "anchor": "Bolted/fixed anchor at base", "notes": "Final rappel to the base of the route."}]'::jsonb, rappel_count_note = 'Individual rappel lengths aren''t given; approximated at the stated single 70m rope capacity since the source doesn''t break out per-pitch distances.' where id = 'wa_ellation';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "Grassy-ledge rappel station (established anchor)", "notes": "First of the 6-8 rap sequence off the upper pitches; a single 60m rope is insufficient for the whole descent."}, {"n": 2, "lengthM": 30, "anchor": "Grassy-ledge rappel station (established anchor)", "notes": "Continuing down the ledge system; ensure adequate redundant anchors at each station."}, {"n": 3, "lengthM": 30, "anchor": "Grassy-ledge rappel station (established anchor)", "notes": "Mid-sequence rappel; terrain and pitch length require full 30m+ raps."}, {"n": 4, "lengthM": 30, "anchor": "Grassy-ledge rappel station (established anchor)", "notes": "Mid-sequence rappel."}, {"n": 5, "lengthM": 30, "anchor": "Grassy-ledge rappel station (established anchor)", "notes": "Mid-sequence rappel."}, {"n": 6, "lengthM": 30, "anchor": "Grassy-ledge rappel station (established anchor)", "notes": "Sixth rappel; some parties finish here depending on rope length and stance spacing."}, {"n": 7, "lengthM": 30, "anchor": "Grassy-ledge rappel station (established anchor)", "notes": "Final rappel for parties needing the full 7-8 rap count; carry a longer rope or extra rappel gear."}]'::jsonb, rappel_count_note = 'Source gives a range of 6-8 raps of 30m+ off a shared grassy-ledge anchor system; individual stations aren''t differentiated in the text, so entries below are representative rather than distinct.' where id = 'wa_junior_s_farm';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "Natural anchor (slung horn/block), trending NE off summit", "notes": "First of three rappels heading northeast from the summit area."}, {"n": 2, "lengthM": 30, "anchor": "Natural/tat anchor, continuing NE trend", "notes": "Second of the three NE-trending rappels."}, {"n": 3, "lengthM": 30, "anchor": "Natural/tat anchor near next rock rib", "notes": "Third rappel; followed by a short, exposed grassy traverse east to the next rock rib before the final two rappels."}, {"n": 4, "lengthM": 30, "anchor": "Mixed natural/fixed anchor above East Ledges", "notes": "First of two rappels dropping onto the East Ledges; a handful of fixed/bolted stations exist along this option."}, {"n": 5, "lengthM": 30, "anchor": "Anchor above East Ledges", "notes": "Final rappel reaching the East Ledges, from which loose class 3-4 ledges/slabs are descended on foot above the Boston Glacier."}]'::jsonb, rappel_count_note = 'The East Ridge itself is not reversed as a rappel line; this covers the alternate ''East Ledges'' descent (~5 raps) used when parties don''t reverse to the West Ridge notch/couloir. Individual lengths aren''t stated, estimated from a 60m rope doubled.' where id = 'wa_forbidden_peak_east_ridge';
update routes set rappel_detail = '[{"n": 1, "lengthM": 35, "anchor": "Bolted anchor (30m-spaced stations, linked via 70m rope)", "notes": "Notable rope friction reported on the pull."}, {"n": 2, "lengthM": 35, "anchor": "Bolted anchor, requires looking right near rope''s end", "notes": "A shiny pair of rap chains mid-route looks like the anchor but isn''t; traverse left to a hidden bolt behind a rock, then further left to the true bolted anchor."}, {"n": 3, "lengthM": 35, "anchor": "Bolted anchor", "notes": "Trends straight down."}, {"n": 4, "lengthM": 35, "anchor": "Bolted anchor at base", "notes": "Straightforward final rappel to the ground."}]'::jsonb, rappel_count_note = NULL where id = 'wa_marvin_s_ear';
update routes set rappel_detail = '[{"n": 1, "lengthM": 55, "anchor": "Fixed anchor at the summit block", "notes": "First double-rope rappel; visually check the fixed anchor before weighting it."}, {"n": 2, "lengthM": 55, "anchor": "Fixed anchor near top of pitch 5", "notes": "Continues down trending climber''s-right; watch for rope snags in chimney/offwidth sections."}, {"n": 3, "lengthM": 55, "anchor": "Fixed anchor, station along route (climber''s right)", "notes": "Third double-rope rappel down the east face."}, {"n": 4, "lengthM": 55, "anchor": "Fixed anchor, final station", "notes": "Last rappel to the base; anchors are fixed but should be checked each time."}]'::jsonb, rappel_count_note = 'Lengths approximated as near-full double-rope rappels using two 60m ropes; exact per-station lengths aren''t given.' where id = 'wa_chianti_spire_east_face';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "P7/summit bolted anchor", "notes": "Drops to the anchor at the base of pitch 7."}, {"n": 2, "lengthM": 30, "anchor": "Bolted anchor left and above the dihedral", "notes": "Face rappel."}, {"n": 3, "lengthM": 15, "anchor": "Ledge-side bolted anchor beside the dihedral", "notes": "Short drop to a ledge."}, {"n": 4, "lengthM": 30, "anchor": "One of two bolted anchors at the pitch 4 stance", "notes": "Two anchor options exist at this stance."}, {"n": 5, "lengthM": 15, "anchor": "Upper-pitch-3 bolted anchor", "notes": "Short, free-hanging rappel aimed at a ~10ft tree left of the line."}, {"n": 6, "lengthM": 30, "anchor": "Bolted anchor at a large ledge, pitch 2 anchors", "notes": "Vertical face rappel down lower pitch 3."}, {"n": 7, "lengthM": 30, "anchor": "Pitch 1 bolted anchor", "notes": "Drops to the pitch 1 station."}, {"n": 8, "lengthM": 30, "anchor": "Base bolted anchor", "notes": "Final rappel to the ground; a single 70m rope is sufficient for the whole sequence."}]'::jsonb, rappel_count_note = 'Per-rappel lengths aren''t stated exactly; approximated from a 70m rope being sufficient for all 8 single-strand raps and the ''short''/''free-hanging'' language on raps 3 and 5.' where id = 'wa_mile_high_club';
update routes set rappel_detail = '[{"n": 1, "lengthM": 55, "anchor": "South-face rappel anchor (rockfall-sheltered)", "notes": "First rappel after traversing the summit ridge to the south-facing anchors."}, {"n": 2, "lengthM": 55, "anchor": "South-face rappel anchor", "notes": "Continuing down the south face."}, {"n": 3, "lengthM": 55, "anchor": "South-face rappel anchor", "notes": "Continuing down the south face."}, {"n": 4, "lengthM": 55, "anchor": "South-face rappel anchor", "notes": "Final rappel before navigating the crevasse field on the Chickamin Glacier back to camp."}]'::jsonb, rappel_count_note = 'Source gives a range of 3-4 rappels on 50-60m lines; 4 used as representative, midpoint length used per rap.' where id = 'wa_east_face';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "Bolted anchor/chains, upper gully", "notes": "First of three single-rope rappels reached after downclimbing the South Arete to the Rabbit Ears."}, {"n": 2, "lengthM": 30, "anchor": "Bolted anchor/chains, mid gully", "notes": "Continuing down the gully system."}, {"n": 3, "lengthM": 30, "anchor": "Bolted anchor/chains, base of gully", "notes": "Final rappel; a 60m rope is used throughout this shared descent line."}]'::jsonb, rappel_count_note = 'The Passenger itself is not commonly rappelled top-to-bottom; this is the shared South Arete descent gully used after downclimbing to the Rabbit Ears.' where id = 'wa_south_early_winter_spire_passenger';
update routes set rappel_detail = '[{"n": 1, "lengthM": 25, "anchor": "Natural anchor (horn/gear/slung block), upper gully", "notes": "First of two rappels protecting a short, sometimes-loose 3rd class gully back to the saddle camp; no fixed anchors, back up any existing tat."}, {"n": 2, "lengthM": 25, "anchor": "Natural anchor, lower gully", "notes": "Second rappel finishing the descent to the saddle camp."}]'::jsonb, rappel_count_note = 'Lengths aren''t stated beyond ''a single 30m rope is sufficient per rappel''; treated as approximate, shorter rappels.' where id = 'wa_bear_mountain_chilliwack_north_buttress';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "Anchor in upper NE-face snowfield (60m rope reaches)", "notes": "First rappel down the upper northeast-face snowfield."}, {"n": 2, "lengthM": 20, "anchor": "Tree anchor, broken terrain", "notes": "Reached via short scramble; rappel down more broken terrain, followed by a short scramble through a notch onto the East Face."}, {"n": 3, "lengthM": 30, "anchor": "Natural/tat anchor on East Face", "notes": "First of two rappels down the East Face toward the Argonaut-Colchuck col."}, {"n": 4, "lengthM": 30, "anchor": "Natural/tat anchor on East Face", "notes": "Final rappel to the base of the East Face."}]'::jsonb, rappel_count_note = 'Lengths for raps 3-4 on the East Face aren''t given; approximated using the 60m-rope note from rap 1.' where id = 'wa_northwest_arete';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "Bolted anchor/chains, upper gully", "notes": "Shared South Arete descent gully; expect delays at stations on busy days since Passenger and other routes share this line."}, {"n": 2, "lengthM": 30, "anchor": "Bolted anchor/chains, mid gully", "notes": "Continuing down the shared gully."}, {"n": 3, "lengthM": 30, "anchor": "Bolted anchor/chains, base of gully", "notes": "Final rappel of the shared South Arete line back toward the Blue Lake basin."}]'::jsonb, rappel_count_note = 'Descent text only says ''several rappels'' along the shared South Arete line; reusing the 3-rappel structure documented for that same named descent (used on this peak by Passenger), since SW Rib explicitly shares it.' where id = 'wa_sews_sw_rib';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "natural horn/block, top of the crux tower", "notes": "First rappel of the shared West Ridge descent, off the crux tower; individual length not stated, estimated from the 60m rope used throughout."}, {"n": 2, "lengthM": 30, "anchor": "natural horn/block, dropping onto north-side snow", "notes": "Second rappel, landing on snow on the north side of the couloir/gully system; exact length not specified in source."}, {"n": 3, "lengthM": 30, "anchor": "natural anchor above the upper moat", "notes": "Explicitly reported as a 30m rappel (60m rope doubled) through the steepest snow section to the top of the upper moat/bergschrund."}]'::jsonb, rappel_count_note = 'NW Face parties join the West Ridge''s own descent at the notch above the south-face couloir. The representative/standard sequence is ~3 rappels in good snow; late-season, dry conditions can push this to 6-7 sequential single-rope rappels down the full Cat Scratch Gullies system, while good consolidated early/mid-season snow can cut it to as few as 1-2 via downclimbing/plunge-stepping.' where id = 'wa_forbidden_peak_northwest_face';
update routes set rappel_detail = '[{"n": 1, "lengthM": 40, "anchor": "large, heavily slung boulder at the summit", "notes": "Drops down the middle of the upper face to a bolted anchor on a ledge."}, {"n": 2, "lengthM": 55, "anchor": "bolted anchor on ledge", "notes": "Down lichen-covered rock to a huge ledge near a rock arch; traverse the ledge to a constriction with slings up to the next anchor."}, {"n": 3, "lengthM": 55, "anchor": "constriction (slung)", "notes": "Down more lichen-covered rock to a horn with a blue sling."}, {"n": 4, "lengthM": 40, "anchor": "horn with blue sling", "notes": "Down to broad, scree-covered upper ledges."}, {"n": 5, "lengthM": 60, "anchor": "top of the first-pitch chimney", "notes": "Final rappel down to the base of the route."}]'::jsonb, rappel_count_note = 'Standard descent is 5 rappels with double 60m ropes; parties using a single 60-70m rope have reportedly gotten down in roughly 4 rappels by adding downclimbing.' where id = 'wa_burgundy_spire_north_face';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "bolted anchor/chains below the Rabbit Ears", "notes": "First of three single-rope rappels down the gully after downclimbing the arete to the Rabbit Ears; length approximate."}, {"n": 2, "lengthM": 30, "anchor": "bolted anchor/chains", "notes": "Continues down the gully; length approximate."}, {"n": 3, "lengthM": 30, "anchor": "bolted anchor/chains at the base", "notes": "Final rappel reaching the base of the formation; length approximate."}]'::jsonb, rappel_count_note = 'Shared with the South Arete''s standard descent; individual per-rappel lengths aren''t given, only the total 3-rappel count and 60m single rope, so ~30m/rappel is estimated from the rope-doubling convention.' where id = 'wa_free_mojo';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "tree, on the 5.0 slab, about 30m below and skier''s-right of the summit exit", "notes": "First rappel, off a tree down a short 5.0 slab from the summit exit area."}, {"n": 2, "lengthM": 30, "anchor": "bolted station (blank section of West Face)", "notes": "First of four bolted single-rope rappels with a 60m rope; per-station length not individually specified, estimated."}, {"n": 3, "lengthM": 30, "anchor": "bolted station", "notes": "Continues down the bolted West Face line; length estimated."}, {"n": 4, "lengthM": 30, "anchor": "bolted station", "notes": "Continues down the bolted West Face line; length estimated."}, {"n": 5, "lengthM": 30, "anchor": "bolted station (lowest)", "notes": "Final bolted rappel reaching the base; length estimated."}]'::jsonb, rappel_count_note = 'This is the current recommended descent (a tree rap near the top followed by four bolted West Face stations). An older/original variant instead makes 5 rappels straight down the ascent gully - including one free-hanging rappel off the chockstone - through loose, windy terrain, and is less commonly used now that the bolted line exists. Individual bolted-station lengths aren''t given in source, only the 60m rope used; ~30m/rappel is an estimate.' where id = 'wa_chockstone_route';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "tree, near the top, ~15ft (4-5m) climber''s-right of the route''s top", "notes": "First rappel, beginning the newer bolted descent shortly after topping out; length approximate, not individually stated."}, {"n": 2, "lengthM": 30, "anchor": "bolted station", "notes": "One of four bolted single-rope rappels down the West Face with a 60m rope; length estimated."}, {"n": 3, "lengthM": 30, "anchor": "bolted station", "notes": "Continues down the bolted line; length estimated."}, {"n": 4, "lengthM": 30, "anchor": "bolted station", "notes": "Continues down the bolted line; length estimated."}, {"n": 5, "lengthM": 30, "anchor": "bolted station (lowest)", "notes": "Final bolted rappel reaching the base; length estimated."}]'::jsonb, rappel_count_note = 'This bolted line (a tree rappel near the top, then four bolted stations) is described as faster/less committing than the original descent, which instead drops skier''s-left through a notch via three single-rope rappels plus one free-hanging rappel over a chockstone, finishing with scrambling. Individual bolted-station lengths aren''t given in source (only that it starts ~15ft/4-5m climber''s-right of the route''s top and uses a 60m rope); ~30m/rappel is an estimate.' where id = 'wa_the_west_face';
update routes set rappel_detail = '[{"n": 1, "lengthM": 25, "anchor": "slung natural anchor (block/chockstone with tat)", "notes": "First of five single-rope rappels down the north-face line east of the summit; most rappels fall in the 25-30m range."}, {"n": 2, "lengthM": 25, "anchor": "slung natural anchor (block/chockstone with tat)", "notes": "Continues down the north-face rappel line; 25-30m range."}, {"n": 3, "lengthM": 25, "anchor": "slung natural anchor (block/chockstone with tat)", "notes": "Continues down the north-face rappel line; 25-30m range."}, {"n": 4, "lengthM": 25, "anchor": "slung natural anchor (block/chockstone with tat)", "notes": "Continues down the north-face rappel line; 25-30m range."}, {"n": 5, "lengthM": 25, "anchor": "slung natural anchor (block/chockstone with tat)", "notes": "Final rappel reaching the base; 25-30m range."}]'::jsonb, rappel_count_note = 'Descent can also be run with two ropes for fewer, longer rappels instead of five single-rope rappels; figure roughly an hour total if no other parties are queued.' where id = 'wa_stanley_burgner';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "bolted anchor/chains below the Rabbit Ears", "notes": "First of three single-rope rappels down the gully after downclimbing the arete to the Rabbit Ears; length approximate."}, {"n": 2, "lengthM": 30, "anchor": "bolted anchor/chains", "notes": "Continues down the gully; length approximate."}, {"n": 3, "lengthM": 30, "anchor": "bolted anchor/chains at the base", "notes": "Final rappel reaching the base of the formation; length approximate."}]'::jsonb, rappel_count_note = 'Shared with the South Arete''s standard descent; individual per-rappel lengths aren''t given, only the total 3-rappel count and 60m single rope, so ~30m/rappel is estimated from the rope-doubling convention.' where id = 'wa_northwest_face_boving_pollock';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "slung horn/block, ~100ft (30m) west of the true summit past a short catwalk", "notes": "First of about three single-rope rappels back to the approach talus; inspect existing fixed slings before weighting."}, {"n": 2, "lengthM": 30, "anchor": "slung horn/block", "notes": "Continues down the east face; length approximate."}, {"n": 3, "lengthM": 30, "anchor": "slung horn/block", "notes": "Final rappel regaining the approach talus at the base."}]'::jsonb, rappel_count_note = 'Approximate count from trip-report beta (~3 rappels); a single 60m rope is reported sufficient throughout, so ~30m/rappel is estimated.' where id = 'wa_east_face_3';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "natural horn/block, top of the crux tower", "notes": "First rappel off the top of the crux tower; individual length not stated in source, estimated from the 60m rope used throughout the descent."}, {"n": 2, "lengthM": 30, "anchor": "natural horn/block, dropping onto north-side snow", "notes": "Second rappel, landing on snow on the north side of the couloir/''Cat Scratch Gullies'' system; exact length not specified."}, {"n": 3, "lengthM": 30, "anchor": "natural anchor above the upper moat", "notes": "Explicitly reported as a 30m rappel (60m rope doubled) through the steepest snow section to the top of the upper moat/bergschrund - the last of the representative 3-rappel sequence before reversing the glacier-remnant/talus traverse back to Boston Basin."}]'::jsonb, rappel_count_note = 'The commonly reported/representative sequence is ~3 rappels, matching the on-file count. In late-season, dry conditions, multiple trip reports describe needing as many as 6-7 sequential single-rope rappels (60m rope) down the full length of the couloir/gully system - don''t skip any anchor, as a couple of stations are intentionally short, and be prepared to build extra stations if the next one isn''t found. In good, consolidated early/mid-season snow, much of the couloir can instead be downclimbed or plunge-stepped, cutting the count to as few as 1-2 rappels. Watch for the bergschrund/moat again near the base of the couloir.' where id = 'wa_forbidden_peak_west_ridge';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "sling around a rock/horn", "notes": "First rappel down steep terrain toward the snow/talus below the notch, off a pre-placed sling on a rock."}, {"n": 2, "lengthM": 30, "anchor": "small tree", "notes": "Second rappel from a small tree, continuing down to the snow slopes; parties then traverse a snow-covered ledge toward the east gully."}]'::jsonb, rappel_count_note = 'Trip-report beta describes two 30m rappels off a slung rock and a small tree; the route''s own metadata field (''4 raps to 30m'') appears to conflate this with a different line (e.g. the Northeast Couloir descent), and the route''s own descent_text explicitly confirms an on-file count of 2.' where id = 'wa_argonaut_peak_east_ridge';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "slung natural block/chockstone", "notes": "First of the north-side rappels off a natural anchor; this line is shared by several south-face routes so expect other parties."}, {"n": 2, "lengthM": 30, "anchor": "slung natural block/chockstone", "notes": "Similar natural-anchor station continuing down the north face."}, {"n": 3, "lengthM": 25, "anchor": "slung natural block/chockstone", "notes": "Stations are unbolted, so back up aged webbing/tat with your own material."}, {"n": 4, "lengthM": 25, "anchor": "slung natural block/chockstone", "notes": "Final rappel of the typical 4-rap sequence (some parties combine to 3 longer rappels using two ropes) reaching the base."}]'::jsonb, rappel_count_note = 'Reported as 3-4 single-rope rappels depending on party choices; some parties run the same line with two ropes for fewer, longer rappels. Shared north-side descent used by multiple South Face routes on Prusik Peak, so expect traffic/queuing.' where id = 'wa_prusik_peak_south_face_burgner_stanley';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "old bolt at the true summit", "notes": "First rappel from a reportedly decades-old bolt anchor at the summit, on a single 60m rope."}, {"n": 2, "lengthM": 30, "anchor": "wedged/chockstone block", "notes": "Anchor looks sketchy but has reportedly held for decades of parties; inspect before committing."}, {"n": 3, "lengthM": 30, "anchor": "slung natural anchor (webbing/tat)", "notes": "Carry extra material to back up aged slings on this and remaining stations."}, {"n": 4, "lengthM": 30, "anchor": "slung natural anchor (webbing/tat)", "notes": "Continue down the north face on natural stations."}, {"n": 5, "lengthM": 30, "anchor": "slung natural anchor (webbing/tat)", "notes": "Continue down the north face on natural stations."}, {"n": 6, "lengthM": 30, "anchor": "slung natural anchor (webbing/tat)", "notes": "Final rappel of the typical sequence; scramble around to the West Ridge base afterward. An extra short rappel is sometimes needed depending on the exact topout point."}]'::jsonb, rappel_count_note = 'Some trip reports mention a possible 6th-or-7th short rappel depending on exactly where the party regains the West Ridge base; 6 is the representative/typical count.' where id = 'wa_beckey_davis';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "bolted station", "notes": "Only bolted anchor on the descent, near the top of pitch 1."}, {"n": 2, "lengthM": 30, "anchor": "gear/piton anchor", "notes": "Mixed gear-and-piton station lower on the north side."}, {"n": 3, "lengthM": 30, "anchor": "slung natural feature", "notes": "Natural anchor; back up older tat with your own webbing."}, {"n": 4, "lengthM": 30, "anchor": "slung natural feature", "notes": "Continue down toward the balanced-rock landmark at the West Ridge base."}, {"n": 5, "lengthM": 30, "anchor": "slung natural feature", "notes": "Fifth of the main sequence, reaching the balanced-rock area."}, {"n": 6, "lengthM": 25, "anchor": "natural anchor near balanced rock", "notes": "Additional single rappel past the balanced-rock landmark to reach easier ground before walking to the South Face base."}]'::jsonb, rappel_count_note = 'Route''s own rappel field lists 5, but the descent text describes an additional single rappel past the balanced-rock landmark before reaching easier ground; treated here as 6 total.' where id = 'wa_prusik_peak_der_sportsman';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "fixed gear/sling anchor", "notes": "First of two single-rope rappels past the West Ridge crux."}, {"n": 2, "lengthM": 30, "anchor": "fixed gear/sling anchor", "notes": "Second single-rope rappel past the crux, followed by a short scramble."}, {"n": 3, "lengthM": 30, "anchor": "fixed gear/sling anchor", "notes": "Another single-rope rappel lower on the West Ridge line."}, {"n": 4, "lengthM": 50, "anchor": "fixed anchor near the notch", "notes": "Double-rope rappel reaching the west notch; from there descend to the basin and Ingalls Creek."}]'::jsonb, rappel_count_note = 'Standard descent traverses to the West Ridge and uses its established rap line rather than reversing the East Ridge; some parties instead reverse the East Ridge directly using roughly 2-4 shorter rappels off fixed slings/chains in the gully system.' where id = 'wa_sherpa_peak_east_ridge';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "bolted station", "notes": "First of the Chockstone Route''s bolted rap stations, used to descend from Labor Pains'' finish."}, {"n": 2, "lengthM": 30, "anchor": "bolted station", "notes": "Stations are reported spaced roughly 100 ft apart down the gully."}, {"n": 3, "lengthM": 30, "anchor": "bolted station (chockstone)", "notes": "Free-hanging rappel off the route''s namesake massive chockstone — one of the more memorable stations on the descent."}, {"n": 4, "lengthM": 30, "anchor": "bolted station", "notes": "Continue down the bolted line toward the base."}, {"n": 5, "lengthM": 30, "anchor": "bolted station / tree", "notes": "Final rappel of the typical sequence before loose gully walking to the ground."}]'::jsonb, rappel_count_note = 'Labor Pains has no independent descent beta of its own — it shares the Chockstone Route''s bolted rappel line. Per outside trip-report/blog beta on the Chockstone Route (one light web search, not in the original source text), the standard descent is reported as roughly 5 rappels off bolted stations spaced about 100 ft (~30m) apart, including a notable free-hanging rappel off the route''s namesake chockstone; a 4-station variant is also reported. Treat this breakdown as approximate shared-route beta, not Labor Pains-specific detail.' where id = 'wa_labor_pains';
update routes set rappel_detail = '[{"n": 1, "lengthM": 5, "anchor": "upper Beckey-route ledge station", "notes": "Short ~20 ft rappel down the upper Beckey Route pitch to a ledge, then traverse left to a tree hung with rap slings."}, {"n": 2, "lengthM": 55, "anchor": "tree with rap slings", "notes": "Single-rope rappel (a 60m rope reaches) to a flatter stance; can be crowded given Beckey Route/South Face traffic."}, {"n": 3, "lengthM": 30, "anchor": "bolted anchor", "notes": "Double-rope rappel (or two single-rope rappels with one rope) reaching the Liberty Bell-Concord notch (~7,300 ft)."}]'::jsonb, rappel_count_note = 'Route''s own field lists 2, but the descent text describes 3 distinct rappels (a short ~20ft lower plus two longer ones); the metadata likely counts only the two main ropelength rappels.' where id = 'wa_liberty_bell_nw_face';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "tree anchor", "notes": "First rappel from a tree just below/west of the true summit, dropping down the NE side toward Pineapple Pass."}, {"n": 2, "lengthM": 30, "anchor": "bolted chain anchor", "notes": "Second rappel to the notch at Pineapple Pass; the rope can pull stiffly, so flake carefully and check the pull direction before committing."}]'::jsonb, rappel_count_note = 'Source describes rappels as reaching ''up to 60m each on a single 60m rope,'' which likely describes the rope''s length rather than true rappel distance; actual per-rap distance is probably closer to the ~25-30m typical of a doubled 60m rope, shown here as approximate.' where id = 'wa_the_tooth_r1';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "bolt/gear anchor on granite", "notes": "First of four consecutive double-rope rappels down the center of the West Face."}, {"n": 2, "lengthM": 30, "anchor": "bolt/gear anchor on granite", "notes": "Continue down the face; manage ropes carefully to avoid tangling on the steep granite."}, {"n": 3, "lengthM": 30, "anchor": "bolt/gear anchor on granite", "notes": "Third rappel of the sequence."}, {"n": 4, "lengthM": 30, "anchor": "bolt/gear anchor on granite", "notes": "Final rappel reaching the base of the route, from which the approach to the Chikamin-Dome Col is reversed."}]'::jsonb, rappel_count_note = NULL where id = 'wa_west_face_2';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "natural sling/webbing anchor (slung summit horn)", "notes": "From the exposed summit horn/ledge, drops to an anchor just above the Class 4 chimney; single 60m rope doubled."}, {"n": 2, "lengthM": 30, "anchor": "natural sling/webbing anchor at chimney top", "notes": "Continues down past the Class 4 chimney to easy talus at the base of the face."}]'::jsonb, rappel_count_note = NULL where id = 'wa_spire_point_southwest_face';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "bolted anchor", "notes": "First of two rappels using a single 60m rope; tie stopper knots since the rappel is close to the rope''s max length."}, {"n": 2, "lengthM": 30, "anchor": "bolted anchor near tree, north end", "notes": "Second rappel reaches the base of the formation."}]'::jsonb, rappel_count_note = 'Can be done as 1 rappel instead with two ropes tied together' where id = 'wa_cobbles_101';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "fixed station near summit", "notes": "First of three single-rope rappels down the south side toward the notch; exact length not given, estimated near single-rope max with a 60m rope."}, {"n": 2, "lengthM": 30, "anchor": "fixed station", "notes": "Second single-rope rappel continuing toward the notch/gully."}, {"n": 3, "lengthM": 30, "anchor": "fixed station at notch/gully", "notes": "Third single-rope rappel reaching the notch between North and South Early Winters Spire."}, {"n": 4, "lengthM": 35, "anchor": "fixed station above chockstone", "notes": "Largely free-hanging double-rope rappel past a huge chockstone (~50 ft/15m of air); exact length not stated in source, estimated as a typical double-rope pitch."}, {"n": 5, "lengthM": 10, "anchor": "tree anchor", "notes": "Final short (~30 ft) rappel, or downclimb/scramble alternative, reaching the base of the Southwest Gully."}]'::jsonb, rappel_count_note = 'Classic notch/chockstone line is described as ''about 4-5 rappels''; final short rappel is sometimes downclimbed instead. A separate bolted West Face line (6 two-bolt stations, single 60m rope barely sufficient) is an alternate descent not detailed here.' where id = 'wa_news_nw_corner';
update routes set rappel_detail = '[{"n": 1, "lengthM": 55, "anchor": "2-bolt anchor (top of P3)", "notes": "Skips the P2 anchor, spanning roughly two pitch-lengths directly to the P1 bolted anchor; likely requires two ropes joined."}, {"n": 2, "lengthM": 30, "anchor": "2-bolt anchor (P1)", "notes": "Reaches the ground from the P1 bolted station."}]'::jsonb, rappel_count_note = 'All stations are 2-bolt anchors with fixed biners; exact pitch lengths not given in source, so lengths below are approximate.' where id = 'wa_liberty_and_injustice_for_all';
update routes set rappel_detail = '[{"n": 1, "lengthM": 10, "anchor": "summit block / northwest shoulder", "notes": "Short ~40 ft single-strand rappel off the true summit''s north side down to the northwest shoulder, anchored at the large rocking summit block."}, {"n": 2, "lengthM": 30, "anchor": "bolted anchor (''Rappel Chimney'', bolts reportedly replaced 2001)", "notes": "Full double-rope rappel down the Rappel Chimney; gets low enough that the remaining descent to the glacier is a downclimb rather than a third rappel. Exact length not stated in source, estimated as a typical double-rope pitch."}]'::jsonb, rappel_count_note = 'Descent narrative explicitly totals 2 rappels; a separate summary field mentions ''5-6 rappels to 30m,'' which conflicts — the detailed descent text is treated as authoritative here.' where id = 'wa_chimney_rock_west_face';
update routes set rappel_detail = '[{"n": 1, "lengthM": 55, "anchor": "top rappel station (SE Face)", "notes": "First of the SE Face double-rope rappels, down the gully/slab system toward the Taboo Glacier."}, {"n": 2, "lengthM": 55, "anchor": "station on climber''s left", "notes": "Second station positioned climber''s left of the fall line."}, {"n": 3, "lengthM": 55, "anchor": "fixed station, straight down/climber''s right", "notes": ""}, {"n": 4, "lengthM": 55, "anchor": "fixed station, straight down/climber''s right", "notes": ""}, {"n": 5, "lengthM": 55, "anchor": "fixed station, straight down/climber''s right", "notes": ""}, {"n": 6, "lengthM": 55, "anchor": "final station above bergschrund/moat", "notes": "Crux rappel: must cross a moat/bergschrund at the bottom to reach the snowfield below."}]'::jsonb, rappel_count_note = 'Reported as 5-6 double-rope rappels down the SE Face; individual station lengths aren''t given explicitly, estimated near-max for a 60m rope used double. An alternate option reverses the South Ridge itself via numerous short single-rope rappels off slings instead.' where id = 'wa_mount_torment_south_ridge';
update routes set rappel_detail = '[{"n": 1, "lengthM": 15, "anchor": "flat spot at/near true summit", "notes": "First station is typically right at your feet from the summit; shorter than the subsequent rappels."}, {"n": 2, "lengthM": 30, "anchor": "fixed slings/tat, rap rings/chain", "notes": "Found by rappelling ~20-30m and looking climber''s-left."}, {"n": 3, "lengthM": 30, "anchor": "fixed slings/tat, rap rings/chain", "notes": ""}, {"n": 4, "lengthM": 30, "anchor": "fixed slings/tat, rap rings/chain", "notes": "Last of the standard rappels down the north side; traverse west across talus to Prusik Pass afterward."}]'::jsonb, rappel_count_note = 'Most parties report 4, some report 5 total; a single 60m rope is adequate at each station for a party of two.' where id = 'wa_prusik_peak_west_ridge';
update routes set rappel_detail = '[{"n": 1, "lengthM": 10, "anchor": "tree/bush anchor", "notes": "First of several rappels descending from the Main/Middle Peak traverse toward Lake Serene."}, {"n": 2, "lengthM": 15, "anchor": "tree/bush anchor", "notes": ""}, {"n": 3, "lengthM": 10, "anchor": "tree/bush anchor", "notes": ""}, {"n": 4, "lengthM": 15, "anchor": "tree/bush anchor", "notes": "Final major station before hiking terrain back to Lake Serene."}]'::jsonb, rappel_count_note = 'Source describes ''multiple short rappels, 3-5 major stations'' with individual raps in the 30-50 ft range; 4 used as a representative count across the North/Middle/Main peak traverse (roughly 2-3 hours total from Main Peak to Lake Serene).' where id = 'wa_traverse_of_mount_index';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "2-bolt station", "notes": "Reached via ~100 ft downclimb through trees/loose rock from the summit; rappels to an intermediate stance."}, {"n": 2, "lengthM": 55, "anchor": "bolted anchor at intermediate stance", "notes": "Double-rope rappel (or two single-rope rappels) down to the Liberty Bell-Concord notch."}]'::jsonb, rappel_count_note = 'Shares the standard notch descent line used by other Liberty Bell routes (Beckey Route, Overexposure); the second half can be done as 2 single-rope rappels instead of 1 double-rope rappel.' where id = 'wa_liberty_bell_east_face';
update routes set rappel_detail = '[{"n": 1, "lengthM": 35, "anchor": "large granite horn with sling anchor", "notes": "First double-rope rappel (~120 ft) from the summit area down to an intermediate anchor on the face."}, {"n": 2, "lengthM": 35, "anchor": "intermediate anchor (re-anchored ropes)", "notes": "Second double-rope rappel completes the descent to the scree base; exact length not stated in source, estimated similar to the first rappel."}]'::jsonb, rappel_count_note = NULL where id = 'wa_east_face_2';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "bolted anchor", "notes": "First of two rappels using a single 60m rope; tie stopper knots since the rappel is close to the rope''s max length."}, {"n": 2, "lengthM": 30, "anchor": "bolted anchor near tree, north end", "notes": "Second rappel reaches the base of the formation."}]'::jsonb, rappel_count_note = 'Can be done as 1 rappel instead with two ropes tied together' where id = 'wa_bowling_alley_aka_regular_route';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "bolted 2-bolt station", "notes": "From the summit/P2-anchor area, downclimb ~100 ft east through trees/loose rock to this station, then rappel to an intermediate stance."}, {"n": 2, "lengthM": 55, "anchor": "bolted anchor at intermediate stance", "notes": "Double-rope rappel (or two single-rope rappels) into the Liberty Bell-Concord notch."}]'::jsonb, rappel_count_note = 'Shares the standard Beckey Route descent line.' where id = 'wa_liberty_bell_overexposure';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "tree hung with rappel slings", "notes": "Single-rope rappel with a 60m rope from the tree station (reached via ~20 ft downclimb of the upper pitch, then left) down to a flatter area."}, {"n": 2, "lengthM": 55, "anchor": "bolted anchor at flatter area", "notes": "Double-rope rappel (or two single-rope rappels if carrying only one rope) reaching the Liberty Bell-Concord notch at ~7,300 ft."}]'::jsonb, rappel_count_note = 'Standard descent line shared by most Liberty Bell summit routes (Overexposure, East Face, etc.).' where id = 'wa_liberty_bell_beckey_route';
update routes set rappel_detail = '[{"n": 1, "lengthM": 60, "anchor": "gear anchor (nuts/small-med cams, occasional slung horn)", "notes": "First rappel off the West Ridge below the notch; no fixed anchors anywhere on this peak, station built fresh from gear."}, {"n": 2, "lengthM": 60, "anchor": "gear anchor (nuts/cams/slung horn)", "notes": "Continuing down the West Ridge rappel line toward the Terror Glacier."}, {"n": 3, "lengthM": 60, "anchor": "gear anchor (nuts/cams/slung horn)", "notes": "Natural anchor built fresh at this station, as at every station on this descent."}, {"n": 4, "lengthM": 60, "anchor": "gear anchor (nuts/cams/slung horn)", "notes": "Mid-line rappel down steep West Ridge terrain."}, {"n": 5, "lengthM": 60, "anchor": "gear anchor (nuts/cams/slung horn)", "notes": "Continuing the descent; two ropes used doubled/joined for close to full-length rappels."}, {"n": 6, "lengthM": 60, "anchor": "gear anchor (nuts/cams/slung horn)", "notes": "Second-to-last rappel before reaching glacier-adjacent terrain."}, {"n": 7, "lengthM": 60, "anchor": "gear anchor (nuts/cams/slung horn)", "notes": "Final rappel reaching the Terror Glacier; unrope and walk off from here."}]'::jsonb, rappel_count_note = 'One trip report logged 7 double-rope (two-rope) rappels of roughly full rope length; a separate party using a single 70m rope doubled instead needed ~14 shorter (~30-35m) rappels to cover the same West Ridge line down to the Terror Glacier. 7 is used here as representative.' where id = 'wa_south_face_5';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "slung rock horn/block", "notes": "First rappel reversing the steepest upper ice/mixed ground below the summit."}, {"n": 2, "lengthM": 30, "anchor": "slung rock horn/block", "notes": "Continuing down through sustained ice terrain; anchors built from slings, not fixed gear."}, {"n": 3, "lengthM": 30, "anchor": "slung rock horn/block", "notes": "Mid-face rappel; some downclimbing/simul-climbing between stations."}, {"n": 4, "lengthM": 30, "anchor": "slung rock horn/block", "notes": "Lower-face rappel through mixed ground."}, {"n": 5, "lengthM": 30, "anchor": "slung rock horn/block", "notes": "Final rappel off the face; carry extra slings since no fixed anchors exist on this line."}]'::jsonb, rappel_count_note = 'Source estimates 4-6 rappels if reversing the face directly (~30m each on a single rope doubled); 5 used as a representative midpoint. Many parties instead traverse over on the upper mountain to descend the easier southwest ''X Couloir'' gully rather than reversing the face.' where id = 'wa_lincoln_peak_north_ridge';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "3 rap rings, backed by sling around tree/horn", "notes": "Topmost station reversing the South Face."}, {"n": 2, "lengthM": 30, "anchor": "8mm doubled cordelette with 2 quicklinks", "notes": "Second rappel down the face."}, {"n": 3, "lengthM": 30, "anchor": "two slung trees", "notes": "Third rappel, well-equipped fixed station."}, {"n": 4, "lengthM": 30, "anchor": "several slings + 3 rap rings around a block", "notes": "Lowest station, reaching Pineapple Pass."}]'::jsonb, rappel_count_note = 'This is the primary reversal-of-route descent (most parties); each rap comes in under 30m on a single 60m rope used doubled. A separate, less-crowded rap line exists on the SW side with bolted chain/ring anchors, and many parties skip rappelling below Pineapple Pass and scramble out instead.' where id = 'wa_the_tooth_south_face';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "bolted station near the top", "notes": "First of four double-rope (60m) rappels straight down the Wright-Pond line."}, {"n": 2, "lengthM": 30, "anchor": "bolted station (P2 end anchor)", "notes": "Second rappel using the bolted P2 belay."}, {"n": 3, "lengthM": 30, "anchor": "intermediate bolted station", "notes": "Third rappel on an intermediate bolted anchor along the line."}, {"n": 4, "lengthM": 30, "anchor": "bolted station (P1 end anchor)", "notes": "Final rappel to the ground using the bolted P1 belay."}]'::jsonb, rappel_count_note = NULL where id = 'wa_wright_pond';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "2-bolt anchor", "notes": "First rappel down to an intermediate stance; length not specified in source, approximate single-rope distance assumed."}, {"n": 2, "lengthM": 55, "anchor": "bolted anchor at intermediate stance", "notes": "Double-rope rappel (or two single-rope rappels) down into the Liberty Bell-Concord notch."}]'::jsonb, rappel_count_note = 'Shares the standard shared summit-descent line used by all Liberty Bell summit routes. Exact length of the first rappel isn''t stated in the source; treated as an approximate single-rope-length rap.' where id = 'wa_liberty_bell_serpentine_crack';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "V-thread (Abalakov) in ice below the dagger", "notes": "First of two short rappels near the summit/upper dagger pitch."}, {"n": 2, "lengthM": 30, "anchor": "V-thread (Abalakov) in ice", "notes": "Second rappel; remaining slabby ice/snow below is downclimbed rather than rappelled."}]'::jsonb, rappel_count_note = NULL where id = 'wa_colfax_peak_polish_route';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "rock horn/buttress station, north side of notch tower", "notes": "Rappel down the steep ice pitch just below the initial downclimb from the notch."}, {"n": 2, "lengthM": 60, "anchor": "tree anchor (old/tattered webbing reported)", "notes": "Full-length rappel (two ropes, or a single 60m) down the climber''s-left entry pitch to the base."}]'::jsonb, rappel_count_note = NULL where id = 'wa_chair_peak_northeast_buttress';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "not specified in source (loose gully terrain)", "notes": "First rappel off the West Ridge Notch; exact anchor type not given in source."}, {"n": 2, "lengthM": 30, "anchor": "not specified in source", "notes": "Continuing down through loose gully terrain, mixed with downclimbing."}, {"n": 3, "lengthM": 30, "anchor": "not specified in source", "notes": "Mid-descent rappel; source doesn''t detail individual stations."}, {"n": 4, "lengthM": 30, "anchor": "not specified in source", "notes": "Rappel through loose gully terrain."}, {"n": 5, "lengthM": 30, "anchor": "not specified in source", "notes": "Rappel/downclimb sequence continues toward the glacier remnants."}, {"n": 6, "lengthM": 30, "anchor": "not specified in source", "notes": "Final rappel(s) reach glacier remnants below the south face where parties can unrope; some parties report a 7th short rappel here."}]'::jsonb, rappel_count_note = 'Source gives a range of roughly 6-7 rappels combined with downclimbing through loose gullies from the West Ridge Notch to the glacier; 6 used as representative. Individual anchor types/lengths aren''t detailed in the source, so lengths below are an approximation based on typical single-rope rappel distance, not confirmed specifics.' where id = 'wa_forbidden_peak_east_face_catscratch';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "trees/rock horn near head of gully", "notes": "First of two double-rope (60m) rappels; some downclimbing needed to reach the next station."}, {"n": 2, "lengthM": 30, "anchor": "not specified in source", "notes": "Second double-rope rappel reaching easier snow near the gully''s base."}]'::jsonb, rappel_count_note = 'Some trip reports instead describe reaching the base with a single 60m rappel plus downclimbing rather than two rappels; 2 used as the more commonly reported sequence.' where id = 'wa_chair_peak_north_face';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "fixed rappel bolts", "notes": "First single-rope rappel from the first set of bolts reached via the tree-filled gully east of the ridge; exact length not given in source, estimated typical single-rope bolt station spacing."}, {"n": 2, "lengthM": 30, "anchor": "fixed rappel bolts", "notes": "Second single-rope rappel reaching the ground in a gully east of the Liberty Bell-Concord notch, a distinct exit from that notch."}]'::jsonb, rappel_count_note = NULL where id = 'wa_rapple_grapple';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "ridge terrain (anchor type not specified)", "notes": "First of two single-rope rappels descending the ridge toward its low point."}, {"n": 2, "lengthM": 30, "anchor": "ridge terrain (anchor type not specified)", "notes": "Second single-rope rappel continuing down to the ridge''s low point."}, {"n": 3, "lengthM": 60, "anchor": "station at ridge low point", "notes": "Long double-rope rappel from the ridge low point back onto the Redoubt Glacier; remote/serious retreat, rappels must be managed carefully."}]'::jsonb, rappel_count_note = NULL where id = 'wa_northwest_mox_peak_standard';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "fixed two-bolt station on a narrow ledge", "notes": "Single-strand rappel from the summit down the uppermost pitch to a two-bolt anchor."}, {"n": 2, "lengthM": 55, "anchor": "large ledge / slung boulder near top of pitch 2", "notes": "Full double-rope-length rappel; break here rather than continuing straight to pitch 2, since a crack just below the top anchor is notorious for wedging ropes."}, {"n": 3, "lengthM": 30, "anchor": "base ledges/gully at start of climb", "notes": "Final rappel from the ledge down to the base ledges/gully where the route began."}]'::jsonb, rappel_count_note = 'Source explicitly describes a 3-rappel standard sequence with a single 60m rope.' where id = 'wa_ingalls_peak_south_ridge';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "fixed/bolted anchor", "notes": "First single-rope rappel down the line of ascent toward the east notch; exact length not given, estimated typical single-rope station spacing."}, {"n": 2, "lengthM": 30, "anchor": "fixed/bolted anchor", "notes": "Second single-rope rappel reaching the east notch, from which parties downclimb the approach gully."}]'::jsonb, rappel_count_note = NULL where id = 'wa_east_wilmans_spire';
update routes set rappel_detail = '[{"n": 1, "lengthM": 20, "anchor": "chockstone/horn or fixed tat-and-ring station", "notes": "First of one-two short rappels off the upper class-4 ridge crest to regain the notch/gully."}, {"n": 2, "lengthM": 20, "anchor": "fixed tat-and-ring or slung horn", "notes": "Second short rappel continuing down to the gully above the glacier."}, {"n": 3, "lengthM": 35, "anchor": "slung chockstone, horn, or old piton station", "notes": "First of two-three longer rappels down the couloir; anchors here are documented as inconsistent quality — inspect and back up."}, {"n": 4, "lengthM": 35, "anchor": "slung chockstone/horn (inspect for single-point natural anchors)", "notes": "A well-documented 2005 accident on this descent involved a single-point natural anchor (one cordelette around a loose block, no backup) that failed under a multi-person rappel and killed three climbers; back up marginal anchors and rappel one at a time."}, {"n": 5, "lengthM": 35, "anchor": "fixed tat-and-ring/slung block near glacier", "notes": "Final rappel down the couloir onto the Quien Sabe Glacier."}]'::jsonb, rappel_count_note = 'Trip reports converge on roughly 4-5 rappels total; used 5 as representative (1-2 short rappels off the upper ridge to regain the notch/gully, then 2-3 longer rappels down the couloir). Anchor quality along this line is documented as inconsistent/marginal.' where id = 'wa_sharkfin_tower_southeast_ridge';
update routes set rappel_detail = '[{"n": 1, "lengthM": 25, "anchor": "slung horn or block (natural)", "notes": "First of two rappels over the fourth-class steps on wet, lower-angle slabs above the glacier; exact distance not stated, source only notes a 50-60m rope is sufficient."}, {"n": 2, "lengthM": 25, "anchor": "slung horn or block (natural)", "notes": "Second rappel reaching the glacier; both use natural horn/block anchors rather than bolts."}]'::jsonb, rappel_count_note = 'Applies to the standard route; the harder Direct East Face variant is reported to need as many as 5-6 rappels instead.' where id = 'wa_east_face_6';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "slung boulder/horn/pedestal (improvised)", "notes": "First of three single-rope (30m) rappels down the summit tower toward a small, exposed high notch."}, {"n": 2, "lengthM": 30, "anchor": "slung boulder/horn/pedestal (improvised)", "notes": "Second single-rope rappel continuing down the tower."}, {"n": 3, "lengthM": 30, "anchor": "slung boulder/horn/pedestal or jammed knot", "notes": "Third single-rope rappel reaching the small exposed high notch."}, {"n": 4, "lengthM": 60, "anchor": "notch station (slung boulder/tat or jammed knot)", "notes": "Longer double-rope rappel from the notch down into the gully/glacier below; all anchors on this route are improvised, not fixed bolts."}]'::jsonb, rappel_count_note = 'Typical late-summer, snow-free count is ~4 rappels (three 30m single-rope + one 60m double-rope). In seasons with a lingering snow finger, parties have needed up to 9-10 shorter rappels interspersed with downclimbing instead.' where id = 'wa_southeast_mox_peak_se_rib';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "summit double-bolt chains", "notes": "First rappel from the summit bolted anchor down the upper North Face."}, {"n": 2, "lengthM": 20, "anchor": "bolted anchor below pitch 3''s 5.0 slab", "notes": "Rappel to the bushy, tree-dotted ledge atop pitch 1."}, {"n": 3, "lengthM": 25, "anchor": "bolted ledge station atop pitch 1", "notes": "Final rappel from the ledge back to the base of the climb at the notch; exact length not explicitly stated in source, estimated similar to the other bolted stations. All anchors on this line are fixed bolts/chains."}]'::jsonb, rappel_count_note = 'The route''s summary line lists 2 rappels (~80-100ft and ~60-80ft), but the more detailed descent description lists 3 distinct bolted rappel stations; used the more detailed 3-rappel account here.' where id = 'wa_concord_tower_north_face';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "slung horn (natural gear anchor)", "notes": "First single-rope rappel down the North Face from the notch below the summit block."}, {"n": 2, "lengthM": 30, "anchor": "slung horn (natural gear anchor)", "notes": "Second rappel regaining the Concord-Lexington col; anchors documented are natural slings around horns, not fixed bolts/chains."}]'::jsonb, rappel_count_note = NULL where id = 'wa_north_face_3';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "bolted chain/bolt station on South Arete descent gully", "notes": "First of the South Arete''s three fixed rappel stations, reached after continuing up to the true summit and downclimbing to the Rabbit Ears; per-rap length not given exactly, kept within single 60m rope range."}, {"n": 2, "lengthM": 30, "anchor": "bolted chain/bolt station", "notes": "Continues down the gully; short easy downclimbing sections connect stations."}, {"n": 3, "lengthM": 30, "anchor": "bolted chain/bolt station", "notes": "Final rappel reaches the base of the South Arete descent gully."}]'::jsonb, rappel_count_note = 'Most parties continue to the true summit and descend via the South Arete''s shared rappel line rather than reversing the Roofs pitch; some reports collapse the South Arete descent to 2 rappels with downclimbing between stations.' where id = 'wa_boving_roofs';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "fixed bolt/chain station, climber''s right of the summer gully/chimney", "notes": "First of three fixed rappel stations equipped in recent years on the South Arete; single 60m rope is sufficient for each rap."}, {"n": 2, "lengthM": 30, "anchor": "fixed bolt/chain station", "notes": "Continues down the arete; short easy downclimbing sections connect stations."}, {"n": 3, "lengthM": 30, "anchor": "fixed bolt/chain station", "notes": "Final rappel returns to the base of the route."}]'::jsonb, rappel_count_note = 'Source says the route ''gets you back to the base... in 2-3 rappels''; 3 is used here as the number of fixed stations described.' where id = 'wa_south_arete';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "natural anchor (slung horn/chockstone) in NW Chimney", "notes": "First of several ~30m rappels dropping through the NW Chimney back toward the glacier; anchors are built from carried gear/tat, no fixed hardware on this route."}, {"n": 2, "lengthM": 30, "anchor": "natural anchor (slung horn/chockstone/tat around boulders)", "notes": "Continues down the chimney."}, {"n": 3, "lengthM": 30, "anchor": "natural anchor near the moat", "notes": "Final rappel(s) typically land at or near the moat where the chimney meets the glacier; a single 60m rope is the practical minimum."}]'::jsonb, rappel_count_note = 'Source describes ''on the order of 3 (or more)'' rappels depending on conditions.' where id = 'wa_cascade_peak_east_ridge';
update routes set rappel_detail = '[{"n": 1, "lengthM": 25, "anchor": "sling around horn/flake", "notes": "First of two single-rope rappels past the 5.4-5.6 crux pitch."}, {"n": 2, "lengthM": 25, "anchor": "sling around horn/flake", "notes": "Second single-rope rappel, reaching a short 3rd-class scramble section."}, {"n": 3, "lengthM": 25, "anchor": "sling around horn/flake (at least one reported station was backed by a questionable wad of slings around small loose rock next to the load-bearing horn)", "notes": "Another single-rope rappel below the scramble."}, {"n": 4, "lengthM": 55, "anchor": "sling anchor near the west notch", "notes": "Longer double-rope rappel (two ropes joined, or a single 60m rope doubled) returning to the west notch below the technical climbing."}]'::jsonb, rappel_count_note = 'Commonly described as four stations (two singles, one single, one double-rope rappel); some trip reports collapse this to three depending on how stations are combined.' where id = 'wa_sherpa_peak_west_ridge';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "slung horn/chockstone at top of chockstone gully", "notes": "First of two rappels down the chimney/chockstone gully used on both ascent and descent."}, {"n": 2, "lengthM": 30, "anchor": "slung horn/chockstone", "notes": "Second rappel continuing down the chimney/gully toward the col notch."}, {"n": 3, "lengthM": 25, "anchor": "anchor at Klawatti-Austera col", "notes": "Roughly 75 ft rappel (or downclimb, depending on moat conditions) dropping onto the Klawatti Glacier where the moat blocks a direct downclimb."}]'::jsonb, rappel_count_note = 'Source estimates 2-3 total rappels depending on conditions: 2 in the summit chimney plus a further short rappel (or downclimb) at the Klawatti-Austera col.' where id = 'wa_austera_peak_southwest_ridge';
update routes set rappel_detail = '[{"n": 1, "lengthM": 25, "anchor": "2-bolt station, no chains or rap rings", "notes": "First 75 ft rappel from the top of pitch 2 back toward the notch; plan to leave a locking biner, rap ring, or cord since there''s no fixed hardware to thread."}, {"n": 2, "lengthM": 25, "anchor": "2-bolt station atop Southeast Ridge pitch 1/2, no chains or rap rings", "notes": "Second 75 ft rappel reaching the ridge notch; a single 60m rope doubled is more than adequate for both raps."}]'::jsonb, rappel_count_note = NULL where id = 'wa_southeast_face';
update routes set rappel_detail = '[{"n": 1, "lengthM": 25, "anchor": "P1 bolted chain anchor", "notes": "Rappel from the P2 anchor down roughly 80 ft to the P1 chain anchor."}, {"n": 2, "lengthM": 30, "anchor": "ground", "notes": "Rappel from the P1 chain anchor roughly 100 ft to the ground; both raps are within single-rope (60m) range."}]'::jsonb, rappel_count_note = NULL where id = 'wa_clast_from_the_past';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "anchor type not specified in source", "notes": "First of two rappels down the climbing route from the summit; watch for loose, pointy rock."}, {"n": 2, "lengthM": 30, "anchor": "anchor type not specified in source", "notes": "Second rappel reaching the base of the tower; climbers use a 60m rope doubled or shorter single-strand raps."}]'::jsonb, rappel_count_note = 'Source gives overall rope usage (60m double-strand, or multiple 30-50m single-strand raps) rather than an exact per-rap length.' where id = 'wa_slippery_slab_tower_ne_face';
update routes set rappel_detail = '[{"n": 1, "lengthM": 25, "anchor": "sling around chockstone/horn", "notes": "First of three rappel stations descending the Southwest Face line; natural (non-bolted) anchors typical of this rock."}, {"n": 2, "lengthM": 25, "anchor": "sling around chockstone/horn", "notes": "Second rappel continuing down the route."}, {"n": 3, "lengthM": 25, "anchor": "sling around chockstone/horn near the notch", "notes": "Final rappel lands past the chockstone into the North-East Peak notch/gully; a single 60m rope is sufficient for all three raps."}]'::jsonb, rappel_count_note = 'Route''s climbing is only 2 pitches, but the standard descent uses three rappel stations retracing the line.' where id = 'wa_ingalls_peak_east_route';
update routes set rappel_detail = '[{"n": 1, "lengthM": 15, "anchor": "gendarme anchor, west side (type not specified in source)", "notes": "First of two rappels down the main gendarmes on the ridge''s west side."}, {"n": 2, "lengthM": 15, "anchor": "gendarme anchor, west side (type not specified in source)", "notes": "Second rappel; total rappelling covers roughly 30m before scrambling down west-slope talus/scree back toward camp."}]'::jsonb, rappel_count_note = NULL where id = 'wa_nw_ridge';
update routes set rappel_detail = '[{"n": 1, "lengthM": 25, "anchor": "bolted double-anchor on ridge crest", "notes": "First rappel from the bolted ridge-crest anchor down to a large ledge/platform."}, {"n": 2, "lengthM": 30, "anchor": "gully anchor (type not specified in source)", "notes": "Second rappel continuing down the Class 4 gully."}, {"n": 3, "lengthM": 30, "anchor": "gully anchor (type not specified in source)", "notes": "Third rappel reaching the base of the route; a single 60m rope used doubled covers all three rappel distances."}]'::jsonb, rappel_count_note = NULL where id = 'wa_mount_cruiser_south_corner';
update routes set rappel_detail = '[{"n": 1, "lengthM": 15, "anchor": "slung boulder/chockstone backed up with cordelette", "notes": "First of two short rappels (source range ~30-60 ft) used where the ledge/gully is snow-covered, icy, or too exposed to downclimb; no fixed or bolted hardware on this route."}, {"n": 2, "lengthM": 15, "anchor": "slung boulder/chockstone backed up with cordelette", "notes": "Second short rappel getting back down to the snowfield/notch area; a single 30m rope is generally sufficient."}]'::jsonb, rappel_count_note = 'Source gives per-rappel length as a 30-60 ft range rather than a fixed figure; midpoint used here.' where id = 'wa_mount_formidable_south_face';
update routes set rappel_detail = '[{"n": 1, "lengthM": 23, "anchor": "natural sling on chockstone/horn", "notes": "Uppermost rappel through the Great Chimney/gully system below the summit; anchors are entirely natural slings (chockstones, horns) with aged, sun-bleached webbing - no bolts on this route."}, {"n": 2, "lengthM": 23, "anchor": "natural sling on chockstone/horn", "notes": "Continues down the chimney/gully; the recommended line threads the low ''keyhole'' tunnel beneath a large chockstone for a clean, low-angle rappel rather than rigging over its lip."}, {"n": 3, "lengthM": 23, "anchor": "natural sling on chockstone/horn", "notes": "Final rappel back down to the South AmBo Saddle; parties who rig over the chockstone''s lip instead of the keyhole get a harder, overhanging drop and sometimes need an extra rappel."}]'::jsonb, rappel_count_note = 'Source reports 2-4 rappels depending on which line is rigged through the chimney (keyhole/tunnel vs. over the chockstone''s lip); 3 used as a representative middle count.' where id = 'wa_american_border_peak_southeast_face';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "single bolt with supplemental cordage", "notes": "First of three rappels heading east off the north face, using a standard 60m rope."}, {"n": 2, "lengthM": 30, "anchor": "single bolt with supplemental cordage", "notes": "Continues the descent toward the east side of the peak."}, {"n": 3, "lengthM": 30, "anchor": "single bolt with supplemental cordage", "notes": "Final rappel, ending near a prominent chockstone chimney; the gully can also be scrambled as an alternative to this rappel sequence."}]'::jsonb, rappel_count_note = NULL where id = 'wa_north_face_of_the_mole';
update routes set rappel_detail = '[{"n": 1, "lengthM": 30, "anchor": "ice V-thread (Abalakov) anchor", "notes": "Double-rope rappel through the upper ice step; anchor is a freshly-built ice screw V-thread/zero-thread - do not reuse old ascent-placed threads. Some downclimbing is mixed in."}, {"n": 2, "lengthM": 30, "anchor": "ice V-thread (Abalakov) anchor", "notes": "Double-rope rappel through the lower ice step back toward the base of the headwall pitches; again built fresh from ice screws, not fixed bolts."}]'::jsonb, rappel_count_note = 'Described as roughly two double-rope rappels overall to clear the steepest ice, but broken down elsewhere as 1-3 rappels through the upper step and 1-2 through the lower step depending on conditions; 2 used as a simplified representative count.' where id = 'wa_mount_rainier_kautz_headwall';
update routes set rappel_detail = '[{"n": 1, "lengthM": 50, "anchor": "small ledge/anchor, east side just below summit", "notes": "Gets down the steepest upper wall; the next rappeller should move off to the side immediately at the bottom rather than straight down, since others may be rappelling above."}, {"n": 2, "lengthM": 60, "anchor": "belay/anchor stance", "notes": "Full-length 60m rappel down to a belay stance; the buttress rock is loose enough that downclimbing is not recommended here."}, {"n": 3, "lengthM": 30, "anchor": "natural anchor (tree, horn, or boulder sling)", "notes": "Overhanging section, typically rigged on doubled rope (~28-30m of actual rappel), ending just below/north of Gunsight Notch; anchors are fixed natural slings/cord rather than bolts - the first station is reportedly a tree at the top of the drop overlooking the V-notch."}]'::jsonb, rappel_count_note = 'Trip-report counts vary: Mountaineers.org describes essentially 3 key rappels (used here for the detail below), other recent trip reports log 4, and Mountain Project notes up to 5 rappels with a 60m rope for margin.' where id = 'wa_mix_up_peak_east_face';
